import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Sparkles, Copy, MessageCircle, CheckCircle2, Loader2, BrainCircuit } from 'lucide-react';
import { useTranslation } from 'react-i18next';

/**
 * AIReportModal — Yapay zeka bütçe analiz raporu modalı
 * Props:
 *   isOpen       — boolean
 *   onClose      — () => void
 *   reportHtml   — string | null (AI'dan gelen HTML)
 *   isLoading    — boolean
 *   error        — string | null
 */
export default function AIReportModal({ isOpen, onClose, reportHtml, isLoading, error }) {
    const { t } = useTranslation();
    const [copied, setCopied] = useState(false);
    const contentRef = useRef(null);
    const [loadingMsgIdx, setLoadingMsgIdx] = useState(0);

    const loadingMessages = [
        t('aiReport.analyzing', { defaultValue: 'Yapay zeka bütçenizi inceliyor...' }),
        t('aiReport.loadingMessages.insights', { defaultValue: 'Harcama alışkanlıklarınız analiz ediliyor...' }),
        t('aiReport.loadingMessages.opportunities', { defaultValue: 'Tasarruf fırsatları değerlendiriliyor...' }),
        t('aiReport.loadingMessages.finalizing', { defaultValue: 'Raporunuz hazırlanıyor...' })
    ];

    useEffect(() => {
        let interval;
        if (isLoading) {
            interval = setInterval(() => {
                setLoadingMsgIdx((prev) => (prev + 1) % loadingMessages.length);
            }, 2500);
        } else {
            setLoadingMsgIdx(0);
        }
        return () => clearInterval(interval);
    }, [isLoading, loadingMessages.length]);

    if (!isOpen) return null;

    const handleCopyText = async () => {
        if (!contentRef.current) return;
        const text = contentRef.current.innerText;
        try {
            await navigator.clipboard.writeText(text);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        } catch {
            // Fallback
            const textarea = document.createElement('textarea');
            textarea.value = text;
            document.body.appendChild(textarea);
            textarea.select();
            document.execCommand('copy');
            document.body.removeChild(textarea);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        }
    };

    const handleWhatsApp = () => {
        if (!contentRef.current) return;
        const text = contentRef.current.innerText;
        const encoded = encodeURIComponent(text);
        window.open(`https://wa.me/?text=${encoded}`, '_blank');
    };

    return (
        <AnimatePresence>
            <motion.div
                className="magic-draft-overlay"
                onClick={onClose}
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
            >
                <motion.div
                    className="ai-report-modal"
                    onClick={e => e.stopPropagation()}
                    initial={{ opacity: 0, y: 40, scale: 0.95 }}
                    animate={{ opacity: 1, y: 0, scale: 1 }}
                    exit={{ opacity: 0, y: 40, scale: 0.95 }}
                    transition={{ type: 'spring', damping: 28, stiffness: 300 }}
                >
                    {/* Header */}
                    <div className="ai-report-header" style={{ background: 'var(--gradient-primary)', borderBottom: 'none', borderRadius: 'var(--radius-xl) var(--radius-xl) 0 0' }}>
                        <div className="flex items-center gap-sm">
                            <Sparkles size={20} style={{ color: 'white' }} />
                            <h3 style={{ fontSize: 'var(--font-lg)', fontWeight: 700, color: 'white' }}>
                                {t('aiReport.title')}
                            </h3>
                        </div>
                        <button className="btn btn-ghost btn-icon" onClick={onClose} style={{ minHeight: 36, width: 36, height: 36, color: 'white' }}>
                            <X size={18} />
                        </button>
                    </div>

                    {/* Content Area */}
                    <div className="ai-report-body">
                        {isLoading && (
                            <div className="ai-report-loading">
                                <motion.div
                                    className="ai-report-loading-icon"
                                    animate={{ scale: [1, 1.1, 1], rotate: [0, 360] }}
                                    transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
                                >
                                    <BrainCircuit size={32} style={{ color: 'var(--accent-purple)' }} />
                                </motion.div>

                                <div style={{ height: 32, display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden', marginTop: 'var(--space-sm)' }}>
                                    <AnimatePresence mode="wait">
                                        <motion.h4
                                            key={loadingMsgIdx}
                                            initial={{ opacity: 0, y: 15 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            exit={{ opacity: 0, y: -15 }}
                                            transition={{ duration: 0.4 }}
                                            style={{ fontSize: 'var(--font-md)', fontWeight: 700, color: 'var(--text-primary)', margin: 0, textAlign: 'center' }}
                                        >
                                            {loadingMessages[loadingMsgIdx]}
                                        </motion.h4>
                                    </AnimatePresence>
                                </div>

                                <p style={{ fontSize: 'var(--font-sm)', color: 'var(--text-secondary)', lineHeight: 1.5, marginTop: 'var(--space-xs)' }}>
                                    {t('aiReport.analyzingDesc', { defaultValue: 'Lütfen bekleyin, bu işlem biraz sürebilir.' })}
                                </p>

                                {/* Premium Skeleton bars */}
                                <div className="ai-report-skeleton mt-lg">
                                    {[1, 2, 3, 4, 5].map((i) => (
                                        <motion.div
                                            key={i}
                                            className={`skeleton-line skeleton-line-${i % 2 === 0 ? 'md' : i === 3 ? 'sm' : 'lg'} premium-shimmer`}
                                            initial={{ opacity: 0, x: -20 }}
                                            animate={{ opacity: 1, x: 0 }}
                                            transition={{ delay: i * 0.1, duration: 0.4 }}
                                        />
                                    ))}
                                </div>
                            </div>
                        )}

                        {error && !isLoading && (
                            <div className="ai-report-error">
                                <p style={{ color: 'var(--accent-red)', fontWeight: 600 }}>⚠️ {error}</p>
                            </div>
                        )}

                        {reportHtml && !isLoading && (
                            <div
                                ref={contentRef}
                                className="ai-report-content"
                                dangerouslySetInnerHTML={{ __html: reportHtml }}
                            />
                        )}
                    </div>

                    {/* Action Buttons */}
                    {reportHtml && !isLoading && (
                        <div className="ai-report-actions">
                            <button
                                className="btn btn-primary flex items-center gap-sm"
                                onClick={handleWhatsApp}
                                style={{ flex: 1, minHeight: 42, borderRadius: 'var(--radius-md)' }}
                            >
                                <MessageCircle size={16} />
                                {t('aiReport.shareWhatsapp')}
                            </button>
                            <button
                                className="btn btn-primary flex items-center gap-sm"
                                onClick={handleCopyText}
                                style={{ flex: 1, minHeight: 42, borderRadius: 'var(--radius-md)' }}
                            >
                                {copied ? (
                                    <>
                                        <CheckCircle2 size={16} />
                                        {t('aiReport.copied')}
                                    </>
                                ) : (
                                    <>
                                        <Copy size={16} />
                                        {t('aiReport.copyText')}
                                    </>
                                )}
                            </button>
                        </div>
                    )}
                </motion.div>
            </motion.div>
        </AnimatePresence>
    );
}

import { useApp } from '../context/AppContext';
import { getInitials, formatRelativeDate, CATEGORIES } from '../utils/helpers';
import { formatCurrency } from '../utils/currencyUtils';
import { Receipt, ArrowLeftRight, UserPlus, CalendarClock } from 'lucide-react';
import { useTranslation } from 'react-i18next';

export default function ActivityFeed({ groupId, limit = 10 }) {
    const { t } = useTranslation();
    const { state } = useApp();

    let activities = [];

    // Expenses as activities
    const expenses = groupId
        ? state.expenses.filter(e => e.groupId === groupId)
        : state.expenses;

    expenses.slice(0, limit).forEach(expense => {
        const payer = state.members[expense.paidBy];
        const group = state.groups.find(g => g.id === expense.groupId);
        const cat = CATEGORIES[expense.category] || CATEGORIES.other;

        activities.push({
            id: expense.id,
            type: 'expense',
            icon: cat.icon,
            iconBg: expense.isRecurring ? 'rgba(245, 158, 11, 0.15)' : 'rgba(139, 92, 246, 0.15)',
            title: expense.description,
            subtitle: `${payer?.name || t('common.someone')} ${t('groups.paid')}${group && !groupId ? ` • ${group.name}` : ''}`,
            amount: formatCurrency(expense.amount, expense.currency),
            amountColor: 'var(--text-primary)',
            date: expense.date,
            isRecurring: expense.isRecurring,
        });
    });

    // Settlements as activities
    const settlements = groupId
        ? state.settlements.filter(s => s.groupId === groupId)
        : state.settlements;

    settlements.slice(0, limit).forEach(settlement => {
        const from = state.members[settlement.from];
        const to = state.members[settlement.to];

        activities.push({
            id: settlement.id,
            type: 'settlement',
            icon: '💸',
            iconBg: settlement.status === 'paid' ? 'rgba(16, 185, 129, 0.15)' : 'rgba(244, 63, 94, 0.15)',
            title: `${from?.name?.split(' ')[0] || '?'} → ${to?.name?.split(' ')[0] || '?'}`,
            subtitle: settlement.status === 'paid' ? t('groups.settled') : t('groups.pending'),
            amount: formatCurrency(settlement.amount, settlement.currency),
            amountColor: settlement.status === 'paid' ? 'var(--accent-emerald)' : 'var(--accent-amber)',
            date: settlement.date,
        });
    });

    // Sort by date descending
    activities.sort((a, b) => new Date(b.date) - new Date(a.date));
    activities = activities.slice(0, limit);

    if (activities.length === 0) {
        return (
            <div className="empty-state" style={{ padding: 'var(--space-xl)' }}>
                <p className="text-sm text-muted">{t('dashboard.noActivity')}</p>
            </div>
        );
    }

    return (
        <div className="flex flex-col">
            {activities.map((activity, i) => (
                <div
                    key={activity.id}
                    className={`flex items-center gap-md animate-fade-in-up stagger-${Math.min(i + 1, 6)}`}
                    style={{
                        padding: 'var(--space-md) 0',
                        borderBottom: i < activities.length - 1 ? '1px solid var(--border-primary)' : 'none',
                    }}
                >
                    <div style={{
                        width: 36,
                        height: 36,
                        borderRadius: 'var(--radius-md)',
                        background: activity.iconBg,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '1rem',
                        flexShrink: 0,
                    }}>
                        {activity.icon}
                    </div>

                    <div style={{ flex: 1, minWidth: 0 }}>
                        <div className="text-sm font-semibold truncate flex items-center gap-sm">
                            {activity.title}
                            {activity.isRecurring && (
                                <CalendarClock size={12} style={{ color: 'var(--accent-amber)', flexShrink: 0 }} />
                            )}
                        </div>
                        <div className="text-xs text-muted">{activity.subtitle}</div>
                    </div>

                    <div style={{ textAlign: 'right', flexShrink: 0 }}>
                        <div className="text-sm font-bold" style={{ color: activity.amountColor }}>
                            {activity.amount}
                        </div>
                        <div className="text-xs text-muted">{formatRelativeDate(activity.date)}</div>
                    </div>
                </div>
            ))}
        </div>
    );
}

import { useRef, useEffect } from 'react';
import { Chart as ChartJS, ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement } from 'chart.js';
import { Doughnut, Bar } from 'react-chartjs-2';
import { useApp } from '../context/AppContext';
import { CATEGORIES } from '../utils/helpers';

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement);

// Override chart defaults for light theme
ChartJS.defaults.color = '#475569';
ChartJS.defaults.borderColor = 'rgba(0,0,0,0.06)';

export function SpendingByCategory({ groupId }) {
    const { state } = useApp();
    const expenses = groupId
        ? state.expenses.filter(e => e.groupId === groupId)
        : state.expenses;

    const categoryTotals = {};
    expenses.forEach(e => {
        const cat = e.category || 'other';
        categoryTotals[cat] = (categoryTotals[cat] || 0) + e.amount;
    });

    const labels = Object.keys(categoryTotals).map(k => CATEGORIES[k]?.label || k);
    const data = Object.values(categoryTotals);
    const colors = [
        '#8b5cf6', '#06b6d4', '#10b981', '#f59e0b',
        '#f43f5e', '#3b82f6', '#ec4899', '#14b8a6', '#64748b'
    ];

    if (data.length === 0) return null;

    return (
        <div style={{ maxWidth: 280, margin: '0 auto' }}>
            <Doughnut
                data={{
                    labels,
                    datasets: [{
                        data,
                        backgroundColor: colors.slice(0, data.length),
                        borderWidth: 0,
                        hoverBorderWidth: 2,
                        hoverBorderColor: 'white',
                        spacing: 2,
                    }],
                }}
                options={{
                    responsive: true,
                    cutout: '65%',
                    plugins: {
                        legend: {
                            position: 'bottom',
                            labels: {
                                padding: 12,
                                usePointStyle: true,
                                pointStyle: 'circle',
                                font: { size: 11, family: 'Inter' },
                            },
                        },
                        tooltip: {
                            backgroundColor: '#ffffff',
                            titleColor: '#0f172a',
                            bodyColor: '#475569',
                            titleFont: { family: 'Inter', weight: 600 },
                            bodyFont: { family: 'Inter' },
                            borderColor: 'rgba(0,0,0,0.1)',
                            borderWidth: 1,
                            padding: 10,
                            cornerRadius: 8,
                            callbacks: {
                                label: (ctx) => {
                                    const total = ctx.dataset.data.reduce((a, b) => a + b, 0);
                                    const pct = ((ctx.raw / total) * 100).toFixed(1);
                                    return ` ${ctx.label}: ${ctx.raw.toLocaleString('tr-TR')} (${pct}%)`;
                                }
                            }
                        },
                    },
                }}
            />
        </div>
    );
}

export function MemberBalanceChart({ groupId }) {
    const { state } = useApp();
    const group = state.groups.find(g => g.id === groupId);
    if (!group) return null;

    const expenses = state.expenses.filter(e => e.groupId === groupId);
    const memberTotals = {};

    group.members.forEach(id => {
        const member = state.members[id];
        if (!member) return;
        const paid = expenses.filter(e => e.paidBy === id).reduce((s, e) => s + e.amount, 0);
        memberTotals[member.name.split(' ')[0]] = paid;
    });

    const labels = Object.keys(memberTotals);
    const data = Object.values(memberTotals);

    if (data.length === 0) return null;

    return (
        <Bar
            data={{
                labels,
                datasets: [{
                    label: 'Harcama',
                    data,
                    backgroundColor: data.map((_, i) => {
                        const colors = [
                            'rgba(139, 92, 246, 0.6)',
                            'rgba(6, 182, 212, 0.6)',
                            'rgba(16, 185, 129, 0.6)',
                            'rgba(245, 158, 11, 0.6)',
                            'rgba(244, 63, 94, 0.6)',
                            'rgba(59, 130, 246, 0.6)',
                        ];
                        return colors[i % colors.length];
                    }),
                    borderColor: data.map((_, i) => {
                        const colors = [
                            'rgba(139, 92, 246, 0.9)',
                            'rgba(6, 182, 212, 0.9)',
                            'rgba(16, 185, 129, 0.9)',
                            'rgba(245, 158, 11, 0.9)',
                            'rgba(244, 63, 94, 0.9)',
                            'rgba(59, 130, 246, 0.9)',
                        ];
                        return colors[i % colors.length];
                    }),
                    borderWidth: 1,
                    borderRadius: 6,
                }],
            }}
            options={{
                responsive: true,
                plugins: {
                    legend: { display: false },
                    tooltip: {
                        backgroundColor: '#ffffff',
                        titleColor: '#0f172a',
                        bodyColor: '#475569',
                        titleFont: { family: 'Inter', weight: 600 },
                        bodyFont: { family: 'Inter' },
                        borderColor: 'rgba(0,0,0,0.1)',
                        borderWidth: 1,
                        padding: 10,
                        cornerRadius: 8,
                    },
                },
                scales: {
                    x: {
                        grid: { display: false },
                        ticks: { font: { family: 'Inter', size: 11 } },
                    },
                    y: {
                        grid: { color: 'rgba(0,0,0,0.04)' },
                        ticks: {
                            font: { family: 'Inter', size: 11 },
                            callback: (v) => v.toLocaleString('tr-TR'),
                        },
                    },
                },
            }}
        />
    );
}

import { useState } from 'react';
import { ArrowRight, Zap, TrendingDown, ChevronDown, ChevronUp, FileText } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { useApp } from '../context/AppContext';
import { calculateBalances, simplifyDebts, getNaiveTransactionCount } from '../utils/debtSimplification';
import { formatCurrency } from '../utils/currencyUtils';
import { getInitials, getAvatarImage } from '../utils/helpers';

export default function DebtSummary({ groupId }) {
    const { t } = useTranslation();
    const { state } = useApp();
    const group = state.groups.find(g => g.id === groupId);
    if (!group) return null;

    const groupMembers = group.members.map(id => state.members[id]).filter(Boolean);
    const groupExpenses = state.expenses.filter(e => e.groupId === groupId);

    if (groupExpenses.length === 0) {
        return (
            <div className="empty-state">
                <div className="empty-icon">🤝</div>
                <h3>{t('dashboard.noDebtsYet')}</h3>
                <p className="text-sm">{t('dashboard.noDebtsYetDesc')}</p>
            </div>
        );
    }

    const [showDetails, setShowDetails] = useState(false);

    const balances = calculateBalances(groupExpenses, groupMembers);
    const transactions = simplifyDebts(balances);
    const naiveCount = getNaiveTransactionCount(groupExpenses);

    // Calculate Raw Transactions
    const rawTransactions = [];
    groupExpenses.forEach(expense => {
        if (!expense.splitAmong || expense.splitAmong.length === 0) return;
        const amountPerPerson = expense.amount / expense.splitAmong.length;
        expense.splitAmong.forEach(borrowerId => {
            if (borrowerId !== expense.paidBy) {
                rawTransactions.push({
                    from: borrowerId,
                    to: expense.paidBy,
                    amount: amountPerPerson,
                    expenseDesc: expense.description
                });
            }
        });
    });

    const getMember = (id) => state.members[id] || { name: 'Bilinmeyen', id };

    return (
        <div className="flex flex-col gap-lg">
            {/* Simplification Stats */}
            <div style={{
                display: 'flex',
                alignItems: 'center',
                gap: 'var(--space-md)',
                padding: 'var(--space-md) var(--space-lg)',
                background: 'rgba(16, 185, 129, 0.08)',
                borderRadius: 'var(--radius-md)',
                border: '1px solid rgba(16, 185, 129, 0.15)',
            }}>
                <Zap size={18} style={{ color: 'var(--accent-emerald)' }} />
                <div className="text-sm">
                    <strong style={{ color: 'var(--accent-emerald-light)' }}>{naiveCount}</strong> {t('groups.possibleTransactions')} →{' '}
                    <strong style={{ color: 'var(--accent-emerald-light)' }}>{transactions.length}</strong> {t('groups.simplifiedTo')}
                    <TrendingDown size={14} style={{ display: 'inline', marginLeft: 4, color: 'var(--accent-emerald)' }} />
                </div>
            </div>

            <div className="flex justify-end">
                <button
                    className="btn btn-ghost btn-sm"
                    onClick={() => setShowDetails(!showDetails)}
                    style={{ color: 'var(--text-secondary)' }}
                >
                    {t('common.showDetails')} {showDetails ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                </button>
            </div>

            {/* Details Accordion */}
            {showDetails && rawTransactions.length > 0 && (
                <div className="animate-fade-in" style={{
                    background: 'var(--bg-glass)',
                    borderRadius: 'var(--radius-md)',
                    padding: 'var(--space-md)',
                    border: '1px solid var(--border-primary)',
                    marginBottom: 'var(--space-md)'
                }}>
                    <h5 className="mb-md flex items-center gap-xs text-sm text-muted">
                        <FileText size={14} /> {t('groups.rawTransactionsBefore')} ({rawTransactions.length})
                    </h5>
                    <div className="flex flex-col gap-sm">
                        {rawTransactions.map((tx, idx) => {
                            const fromMember = getMember(tx.from);
                            const toMember = getMember(tx.to);
                            return (
                                <div key={idx} className="flex justify-between items-center" style={{ fontSize: 'var(--font-xs)' }}>
                                    <div className="flex items-center gap-xs text-tertiary" style={{ flex: 1, minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                        <span className="font-semibold">{fromMember.name.split(' ')[0]}</span>
                                        <ArrowRight size={10} />
                                        <span className="font-semibold">{toMember.name.split(' ')[0]}</span>
                                    </div>
                                    <div className="flex items-center gap-sm">
                                        <span className="text-muted truncate" style={{ maxWidth: 100 }}>{tx.expenseDesc}</span>
                                        <span className="font-bold text-amber-500">{formatCurrency(tx.amount, group.currency)}</span>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            {/* Transaction List */}
            {transactions.map((tx, i) => {
                const fromMember = getMember(tx.from);
                const toMember = getMember(tx.to);

                return (
                    <div key={i} className={`debt-arrow animate-fade-in-up stagger-${i + 1}`}>
                        {/* From */}
                        <div className="flex items-center gap-sm" style={{ minWidth: 0, flex: '0 0 auto' }}>
                            <img src={getAvatarImage(fromMember.avatarId || 1)} alt={fromMember.name} className="avatar avatar-sm" style={{ objectFit: 'cover' }} />
                            <span className="text-sm font-semibold truncate" style={{ maxWidth: 80 }}>
                                {fromMember.name.split(' ')[0]}
                            </span>
                        </div>

                        {/* Arrow with amount */}
                        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2 }}>
                            <span className="text-sm font-bold" style={{ color: 'var(--accent-amber-light)' }}>
                                {formatCurrency(tx.amount, group.currency)}
                            </span>
                            <div style={{
                                width: '100%',
                                height: 2,
                                background: 'var(--gradient-primary)',
                                position: 'relative',
                            }}>
                                <ArrowRight
                                    size={16}
                                    style={{
                                        position: 'absolute',
                                        right: -2,
                                        top: '50%',
                                        transform: 'translateY(-50%)',
                                        color: 'var(--accent-cyan)',
                                    }}
                                />
                            </div>
                        </div>

                        {/* To */}
                        <div className="flex items-center gap-sm" style={{ minWidth: 0, flex: '0 0 auto' }}>
                            <img src={getAvatarImage(toMember.avatarId || 1)} alt={toMember.name} className="avatar avatar-sm" style={{ objectFit: 'cover' }} />
                            <span className="text-sm font-semibold truncate" style={{ maxWidth: 80 }}>
                                {toMember.name.split(' ')[0]}
                            </span>
                        </div>
                    </div>
                );
            })}

            {transactions.length === 0 && (
                <div className="empty-state">
                    <div className="empty-icon">✅</div>
                    <h3>{t('dashboard.allDebtsEqual')}</h3>
                    <p className="text-sm">{t('groups.noDebtsDesc')}</p>
                </div>
            )}
        </div>
    );
}

import { useNavigate } from 'react-router-dom';
import { Users, ArrowRight, TrendingUp, TrendingDown } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { getInitials, getAvatarImage } from '../utils/helpers';
import { formatCurrency } from '../utils/currencyUtils';
import { calculateBalances } from '../utils/debtSimplification';
import { useTranslation } from 'react-i18next';

export default function GroupCard({ group, index }) {
    const navigate = useNavigate();
    const { state } = useApp();
    const { t } = useTranslation();

    const groupMembers = group.members.map(id => state.members[id]).filter(Boolean);
    const groupExpenses = state.expenses.filter(e => e.groupId === group.id);

    const totalSpent = groupExpenses.reduce((sum, e) => sum + e.amount, 0);

    // Calculate current user's balance
    const balances = calculateBalances(groupExpenses, groupMembers);
    const myBalance = balances[state.currentUser] || 0;

    return (
        <div
            className={`glass-card animate-fade-in-up stagger-${index + 1}`}
            style={{ cursor: 'pointer' }}
            onClick={() => navigate(`/group/${group.id}`)}
        >
            {/* Color accent bar */}
            <div style={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                height: '3px',
                background: `linear-gradient(90deg, ${group.color || 'var(--accent-purple)'}, transparent)`,
            }} />

            <div className="flex items-center justify-between mb-md">
                <h4 style={{ fontSize: 'var(--font-md)' }}>{group.name}</h4>
                <ArrowRight size={16} style={{ color: 'var(--text-muted)' }} />
            </div>

            <p className="text-sm text-muted mb-lg">{group.description}</p>

            {/* Member Avatars */}
            <div className="flex items-center justify-between mb-lg">
                <div className="avatar-stack">
                    {groupMembers.slice(0, 4).map((member) => (
                        <img
                            key={member.id}
                            src={getAvatarImage(member.avatarId || 1)}
                            alt={member.name}
                            className="avatar avatar-sm"
                            style={{ objectFit: 'cover' }}
                            title={member.name}
                        />
                    ))}
                    {groupMembers.length > 4 && (
                        <div className="avatar avatar-sm" style={{ background: 'var(--bg-tertiary)', fontSize: '0.6rem' }}>
                            +{groupMembers.length - 4}
                        </div>
                    )}
                </div>
                <span className="badge badge-purple">
                    <Users size={10} /> {groupMembers.length} {t('groupCard.members')}
                </span>
            </div>

            {/* Stats */}
            <div style={{
                display: 'grid', gridTemplateColumns: '1fr 1fr',
                gap: 'var(--space-md)',
                padding: 'var(--space-md)',
                background: 'var(--bg-glass)',
                borderRadius: 'var(--radius-md)',
            }}>
                <div>
                    <div className="text-xs text-muted">{t('groupCard.totalExpense')}</div>
                    <div className="font-bold" style={{ color: 'var(--text-primary)', fontSize: 'var(--font-base)' }}>
                        {formatCurrency(totalSpent, group.currency)}
                    </div>
                </div>
                <div style={{ textAlign: 'right' }}>
                    <div className="text-xs text-muted">{t('groupCard.yourBalance')}</div>
                    <div className="font-bold flex items-center justify-end gap-xs" style={{
                        color: myBalance >= 0 ? 'var(--accent-emerald)' : 'var(--accent-rose)',
                        fontSize: 'var(--font-base)',
                    }}>
                        {myBalance >= 0 ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
                        {formatCurrency(myBalance, group.currency)}
                    </div>
                </div>
            </div>
        </div>
    );
}

