import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { NavLink, useLocation, useNavigate, Outlet } from 'react-router-dom';
import {
    LayoutDashboard, Users, PlusCircle, ArrowLeftRight,
    BarChart3, Settings, Receipt, Bell, LogOut, CircleUser,
    Wallet, Plus, User, X, Sparkles
} from 'lucide-react';
import { useApp } from '../context/AppContext';
import appIconImg from '../../assets/icon.png';
import NotificationMenu from './NotificationMenu';
import ProBenefitsMenu from './ProBenefitsMenu';
import ProUpgradeModal from './ProUpgradeModal';
import UpgradeBanner from './UpgradeBanner';
import { Star } from 'lucide-react';
import { showInterstitialAd } from '../utils/adService';
import FloatingActionMenu from './ui/FloatingActionMenu';
import RecurringPromptModal from './RecurringPromptModal';
import MagicDraftModal from './MagicDraftModal';
import { getPendingRecurringExpenses } from '../utils/recurringUtils';
import InteractiveMenu from './ui/InteractiveMenu';

export default function Layout() {
    const { t } = useTranslation();
    const location = useLocation();
    const navigate = useNavigate();
    const { state } = useApp();
    const [showNotifications, setShowNotifications] = useState(false);
    const [showProBenefits, setShowProBenefits] = useState(false);
    const [showProModal, setShowProModal] = useState(false);
    const [showUpgradeBanner, setShowUpgradeBanner] = useState(false);

    // Recurring expenses
    const [showRecurringModal, setShowRecurringModal] = useState(false);
    const [pendingRecurring, setPendingRecurring] = useState([]);
    const [showMagicDraft, setShowMagicDraft] = useState(false);

    const isPro = state.members[state.currentUser]?.isPro;

    const currentTheme = state.settings?.theme || 'light';
    const iconSrc = currentTheme === 'dark' ? `${import.meta.env.BASE_URL}icondark.png` : appIconImg;
    const iconBg = currentTheme === 'dark' ? 'transparent' : 'white';

    // Track route changes and show ad on the 2nd change
    useEffect(() => {
        // Skip ad check entirely for Pro users
        if (isPro) return;

        // Retrieve the current counter from sessionStorage to handle hard reloads
        const currentCount = parseInt(sessionStorage.getItem('routeChangeCount') || '0', 10);
        const newCount = currentCount + 1;

        sessionStorage.setItem('routeChangeCount', newCount.toString());

        // Show interstitial ad every 3 page transitions (3, 6, 9...)
        if (newCount > 1 && newCount % 3 === 0) {
            showInterstitialAd();
        }
    }, [location.pathname, isPro]);

    useEffect(() => {
        const handler = () => {
            setShowUpgradeBanner(true);
            // Auto hide after 5 seconds
            setTimeout(() => setShowUpgradeBanner(false), 5000);
        };
        window.addEventListener('show-pro-banner', handler);
        return () => window.removeEventListener('show-pro-banner', handler);
    }, []);

    // Check for pending recurring expenses once per session when data is loaded
    useEffect(() => {
        if (!state.currentUser || pendingRecurring.length > 0 || sessionStorage.getItem('recurringCheckedToday')) return;

        // Make sure data is mostly loaded. Since we are inside Layout, AppContext is providing state.
        if (state.expenses.length > 0 || state.personalExpenses.length > 0) {
            const pendingGroup = getPendingRecurringExpenses(state.expenses);
            const pendingPersonal = getPendingRecurringExpenses(state.personalExpenses);
            const allPending = [...pendingGroup, ...pendingPersonal];

            if (allPending.length > 0) {
                setPendingRecurring(allPending);
                setShowRecurringModal(true);
            }
            sessionStorage.setItem('recurringCheckedToday', 'true');
        }
    }, [state.expenses, state.personalExpenses, state.currentUser, pendingRecurring.length]);

    const pendingCount = state.settlements.filter(s => s.status !== 'paid').length;

    const navItems = [
        { to: '/dashboard', icon: LayoutDashboard, label: t('nav.dashboard') },
        { to: '/wallet', icon: Wallet, label: t('nav.wallet') },
        { to: '/groups', icon: Users, label: t('nav.groups') },
        { to: '/add-expense', icon: PlusCircle, label: t('nav.addExpense') },
        { to: '/settlements', icon: ArrowLeftRight, label: t('nav.settlements'), badge: pendingCount || null },
        { to: '/reports', icon: BarChart3, label: t('nav.reports') },
        { to: '/profile', icon: CircleUser, label: t('nav.profile') },
    ];

    const interactiveMenuItems = [
        { to: '/wallet', icon: Wallet, label: 'nav.wallet' },
        { to: '/groups', icon: Users, label: 'nav.groups' },
        { to: '/settlements', icon: ArrowLeftRight, label: 'nav.settlements' },
        { to: '/reports', icon: BarChart3, label: 'nav.reports' },
        { to: '/profile', icon: CircleUser, label: 'nav.profile' },
    ];

    return (
        <div className="app-layout">
            {/* Desktop Sidebar */}
            <aside className="sidebar">
                <div className="sidebar-header" style={{ padding: 'var(--space-md) var(--space-xl)' }}>
                    <div className="sidebar-logo" style={{ justifyContent: 'center' }}>
                        <img src={iconSrc} alt="CoBill" style={{ width: 60, height: 60, borderRadius: '12px', objectFit: 'contain', background: iconBg }} />
                    </div>
                </div>

                <nav className="sidebar-nav">
                    <span className="sidebar-section-label">{t('nav.mainMenu')}</span>
                    {navItems.map(item => (
                        <NavLink
                            key={item.to}
                            to={item.to}
                            className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
                            end={item.to === '/dashboard'}
                        >
                            <item.icon size={18} />
                            <span>{item.label}</span>
                            {item.badge && <span className="nav-badge">{item.badge}</span>}
                        </NavLink>
                    ))}

                    <span className="sidebar-section-label" style={{ marginTop: 'var(--space-lg)' }}>{t('nav.myGroups')}</span>
                    {state.groups.map(group => (
                        <NavLink
                            key={group.id}
                            to={`/group/${group.id}`}
                            className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
                        >
                            <span style={{ fontSize: '1.1rem' }}>{group.name.split(' ')[0]}</span>
                            <span className="truncate">{group.name.replace(/^[^\s]+\s/, '')}</span>
                        </NavLink>
                    ))}
                </nav>

                <div className="sidebar-footer">
                    {!isPro && (
                        <div
                            className="nav-item animate-pulse-subtle"
                            onClick={() => setShowProModal(true)}
                            style={{
                                cursor: 'pointer',
                                background: 'var(--gradient-primary)',
                                color: 'white',
                                borderRadius: 'var(--radius-md)',
                                marginBottom: 'var(--space-md)',
                                padding: 'var(--space-md)',
                                border: 'none'
                            }}
                        >
                            <Star size={18} fill="white" />
                            <span style={{ fontWeight: 700 }}>{t('nav.goToPro')}</span>
                        </div>
                    )}
                    <div className="nav-item" onClick={() => navigate('/profile')} style={{ cursor: 'pointer', justifyContent: 'flex-start' }}>
                        <div className="avatar avatar-sm" style={{ background: 'var(--gradient-primary)' }}>
                            {state.members[state.currentUser]?.name?.[0] || 'U'}
                        </div>
                        <div style={{ flex: 1, minWidth: 0 }}>
                            <div className="text-sm font-semibold truncate">
                                {state.members[state.currentUser]?.name || t('common.user')}
                            </div>
                            <div className="text-xs text-muted">{isPro ? t('common.proPlan') : t('common.freePlan')}</div>
                        </div>
                    </div>
                </div>
            </aside>

            {/* Main Content */}
            <main className="main-content" style={{ paddingBottom: '0' }}>
                {/* DÜZELTME: Mobile Header buraya, main-content içine taşındı! 
                  Böylece Flexbox onu sayfanın soluna itip boşluk yaratmayacak.
                */}
                <header className="mobile-header">
                    {/* Left CTA: PRO */}
                    {!isPro && (
                        <div style={{ position: 'absolute', left: 'var(--space-md)' }} className="hide-desktop">
                            <div style={{ position: 'relative' }}>
                                <button
                                    className="btn-pro-gold flex items-center justify-center animate-pulse-subtle"
                                    style={{
                                        width: 38,
                                        height: 38,
                                        borderRadius: '50%',
                                        padding: 0,
                                        boxShadow: '0 4px 15px rgba(217, 119, 6, 0.4)',
                                        border: '2px solid rgba(251, 191, 36, 0.5)'
                                    }}
                                    onClick={() => setShowProBenefits(!showProBenefits)}
                                >
                                    <Star size={20} fill="currentColor" />
                                </button>
                                <div style={{
                                    position: 'absolute',
                                    top: '-4px',
                                    right: '-4px', // Moved badge to right so it doesn't clip off-screen left
                                    background: 'var(--gradient-primary)',
                                    color: 'white',
                                    fontSize: '8px',
                                    fontWeight: 900,
                                    padding: '2px 4px',
                                    borderRadius: '4px',
                                    boxShadow: '0 2px 10px rgba(0,0,0,0.3)',
                                    border: '1px solid rgba(255,255,255,0.2)',
                                    zIndex: 10
                                }}>
                                    PRO
                                </div>
                            </div>
                            {showProBenefits && (
                                <ProBenefitsMenu
                                    onClose={() => setShowProBenefits(false)}
                                    onUpgrade={() => {
                                        setShowProBenefits(false);
                                        setShowProModal(true);
                                    }}
                                    isMobile={true}
                                />
                            )}
                        </div>
                    )}

                    <div className="sidebar-logo">
                        <img src={iconSrc} alt="CoBill" style={{ width: 96, height: 96, borderRadius: '14px', objectFit: 'contain', background: iconBg }} />
                    </div>

                    <div style={{ position: 'absolute', right: 'var(--space-md)' }}>
                        <button
                            className="btn btn-ghost btn-icon"
                            onClick={(e) => {
                                setShowNotifications(!showNotifications);
                                // Titreme animasyonu efekti
                                const btn = e.currentTarget.querySelector('svg');
                                btn.classList.remove('animate-ring');
                                void btn.offsetWidth; // trigger reflow
                                btn.classList.add('animate-ring');
                            }}
                        >
                            <Bell size={22} className="bell-icon-svg" />
                            {/* NotificationMenu handles the red dot Badge logic internally if passed right */}
                        </button>
                        {showNotifications && (
                            <NotificationMenu onClose={() => setShowNotifications(false)} isMobile={true} />
                        )}
                    </div>
                </header>

                <div className="page-content">
                    <Outlet />
                </div>
            </main>

            {/* Global FAB (Mobile) */}
            <div className="hide-desktop">
                <FloatingActionMenu
                    options={[
                        {
                            label: t('fab.magicDraft'),
                            description: t('fab.magicDraftDesc'),
                            onClick: () => setShowMagicDraft(true),
                            Icon: <Sparkles size={22} />,
                            color: 'var(--accent-amber)'
                        },
                        {
                            label: t('fab.personalExpense'),
                            description: t('fab.personalExpenseDesc'),
                            onClick: () => navigate('/add-personal'),
                            Icon: <User size={22} />,
                            color: 'var(--accent-purple)'
                        },
                        {
                            label: t('fab.groupExpense'),
                            description: t('fab.groupExpenseDesc'),
                            onClick: () => navigate('/add-expense'),
                            Icon: <Users size={22} />,
                            color: 'var(--accent-cyan)'
                        }
                    ]}
                />
            </div>

            {/* Mobile Bottom Tab Bar */}
            <div className="mobile-tab-bar">
                <InteractiveMenu
                    items={interactiveMenuItems}
                    accentColor="var(--accent-purple)"
                />
            </div>

            {/* Upgrade Banner for Pro Features */}
            {!isPro && (
                <UpgradeBanner
                    visible={showUpgradeBanner}
                    onClose={() => setShowUpgradeBanner(false)}
                    onUpgrade={() => {
                        setShowUpgradeBanner(false);
                        setShowProModal(true);
                    }}
                />
            )}

            {/* Modals */}
            {showProModal && (
                <ProUpgradeModal onClose={() => setShowProModal(false)} />
            )}
            {showMagicDraft && (
                <MagicDraftModal onClose={() => setShowMagicDraft(false)} />
            )}
        </div>
    );
}

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, X, Check, Loader2, Users, User, AlertCircle } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { parseMagicDraft, AI_CATEGORIES } from '../services/aiService';
import { generateId } from '../utils/helpers';
import { useTranslation } from 'react-i18next';

const CATEGORY_ICONS = {
    'Market': '🛒',
    'Fatura': '📋',
    'Eğitim': '📚',
    'Eğlence': '🎬',
    'Ulaşım': '🚕',
    'Diğer': '📦',
};

export default function MagicDraftModal({ onClose }) {
    const { state, dispatch } = useApp();
    const { t } = useTranslation();

    const [inputText, setInputText] = useState('');
    const [drafts, setDrafts] = useState([]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');
    const [savingId, setSavingId] = useState(null);
    const [isComplete, setIsComplete] = useState(false);

    // Ayrıştır butonu
    const handleParse = async () => {
        if (!inputText.trim() || isLoading) return;
        setError('');
        setIsLoading(true);

        try {
            const results = await parseMagicDraft(inputText.trim());
            if (!results || results.length === 0) {
                setError(t('magicDraft.noResults'));
                setIsLoading(false);
                return;
            }
            // Her sonuç için düzenlenebilir taslak oluştur
            const newDrafts = results.map(item => ({
                _draftId: generateId(),
                amount: item.amount,
                title: item.title,
                category: item.category,
                date: item.date,
                currency: item.currency || state.settings?.defaultCurrency || 'TRY',
                expenseType: 'personal', // 'personal' | 'group'
                groupId: '',
                paidBy: state.currentUser,
                saved: false,
            }));
            setDrafts(prev => [...prev, ...newDrafts]);
        } catch (err) {
            setError(err.message || t('magicDraft.parseError'));
        } finally {
            setIsLoading(false);
        }
    };

    // Taslak alanını güncelle
    const updateDraft = (draftId, field, value) => {
        setDrafts(prev => prev.map(d =>
            d._draftId === draftId ? { ...d, [field]: value } : d
        ));
    };

    // Grup değiştiğinde paidBy ve splitAmong güncelle
    const handleGroupChange = (draftId, groupId) => {
        const group = state.groups.find(g => g.id === groupId);
        setDrafts(prev => prev.map(d =>
            d._draftId === draftId
                ? {
                    ...d,
                    groupId,
                    paidBy: group?.members?.includes(state.currentUser) ? state.currentUser : (group?.members?.[0] || state.currentUser),
                }
                : d
        ));
    };

    // Kaydet
    const handleSave = async (draft) => {
        if (savingId) return;

        // Validation: grup masrafıysa grup seçilmiş olmalı
        if (draft.expenseType === 'group' && !draft.groupId) {
            setError(t('magicDraft.selectGroupFirst'));
            return;
        }

        setSavingId(draft._draftId);
        setError('');

        try {
            if (draft.expenseType === 'personal') {
                const personalExpense = {
                    id: generateId(),
                    amount: parseFloat(draft.amount),
                    currency: draft.currency,
                    title: draft.title,
                    category: draft.category,
                    date: new Date(draft.date).toISOString(),
                    userId: state.currentUser,
                    isRecurring: false,
                    nextRecurringDate: null,
                };
                await dispatch({ type: 'ADD_PERSONAL_EXPENSE', payload: personalExpense });
            } else {
                // Grup masrafı
                const group = state.groups.find(g => g.id === draft.groupId);
                const expense = {
                    id: generateId(),
                    groupId: draft.groupId,
                    description: draft.title,
                    amount: parseFloat(draft.amount),
                    currency: draft.currency,
                    paidBy: draft.paidBy,
                    splitAmong: group?.members || [],
                    splitType: 'equal',
                    category: draft.category.toLowerCase() === 'market' ? 'shopping' :
                        draft.category.toLowerCase() === 'fatura' ? 'bills' :
                            draft.category.toLowerCase() === 'eğlence' ? 'entertainment' :
                                draft.category.toLowerCase() === 'ulaşım' ? 'transport' :
                                    'other',
                    date: new Date(draft.date).toISOString(),
                    isRecurring: false,
                    nextRecurringDate: null,
                };
                await dispatch({ type: 'ADD_EXPENSE', payload: expense });
            }

            // Kartı başarılı olarak işaretle, kısa süre sonra kaldır
            setDrafts(prev => prev.map(d =>
                d._draftId === draft._draftId ? { ...d, saved: true } : d
            ));
            setTimeout(() => {
                setDrafts(prev => {
                    const remaining = prev.filter(d => d._draftId !== draft._draftId);
                    if (remaining.length === 0 && prev.length > 0) {
                        setIsComplete(true);
                        setTimeout(() => {
                            onClose();
                        }, 1500);
                    }
                    return remaining;
                });
            }, 600);
        } catch (err) {
            setError(err.message || t('magicDraft.saveError'));
        } finally {
            setSavingId(null);
        }
    };

    const activeDrafts = drafts.filter(d => !d.saved);

    return (
        <div className="magic-draft-overlay" onClick={onClose}>
            <motion.div
                className="magic-draft-sheet"
                onClick={e => e.stopPropagation()}
                initial={{ y: '100%' }}
                animate={{ y: 0 }}
                exit={{ y: '100%' }}
                transition={{ type: 'spring', damping: 30, stiffness: 300 }}
            >
                {/* Header */}
                <div className="magic-draft-header">
                    <div className="flex items-center gap-sm">
                        <Sparkles size={20} style={{ color: 'var(--accent-amber)' }} />
                        <h3 style={{ fontSize: 'var(--font-lg)', fontWeight: 700 }}>
                            {t('magicDraft.title')}
                        </h3>
                    </div>
                    <button className="btn btn-ghost btn-icon" onClick={onClose} style={{ minHeight: 36, width: 36, height: 36 }}>
                        <X size={18} />
                    </button>
                </div>

                {/* Drag handle */}
                <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 'var(--space-md)' }}>
                    <div style={{
                        width: 40, height: 4,
                        borderRadius: 'var(--radius-full)',
                        background: 'var(--border-secondary)',
                    }} />
                </div>

                {/* Input Area */}
                <div className="magic-draft-input-area">
                    <textarea
                        className="form-textarea magic-draft-textarea"
                        placeholder={t('magicDraft.placeholder')}
                        value={inputText}
                        onChange={e => setInputText(e.target.value)}
                        rows={3}
                    />
                    <button
                        className="btn btn-primary w-full"
                        onClick={handleParse}
                        disabled={!inputText.trim() || isLoading}
                        style={{ borderRadius: 'var(--radius-md)' }}
                    >
                        {isLoading ? (
                            <span className="flex items-center gap-sm">
                                <Loader2 size={18} className="magic-draft-spinner" />
                                {t('magicDraft.parsing')}
                            </span>
                        ) : (
                            <span className="flex items-center gap-sm">
                                <Sparkles size={18} />
                                {t('magicDraft.parseButton')}
                            </span>
                        )}
                    </button>
                </div>

                {/* Error */}
                <AnimatePresence>
                    {error && (
                        <motion.div
                            className="magic-draft-error"
                            initial={{ opacity: 0, height: 0 }}
                            animate={{ opacity: 1, height: 'auto' }}
                            exit={{ opacity: 0, height: 0 }}
                        >
                            <AlertCircle size={16} />
                            <span>{error}</span>
                        </motion.div>
                    )}
                </AnimatePresence>

                {/* Loading Skeleton */}
                {isLoading && (
                    <div className="magic-draft-skeletons">
                        {[1, 2].map(i => (
                            <div key={i} className="magic-draft-skeleton-card">
                                <div className="skeleton-line skeleton-line-sm" />
                                <div className="skeleton-line skeleton-line-lg" />
                                <div className="skeleton-line skeleton-line-md" />
                            </div>
                        ))}
                    </div>
                )}

                {/* Success State */}
                <AnimatePresence>
                    {isComplete && (
                        <motion.div
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.8 }}
                            className="flex flex-col items-center justify-center p-2xl gap-md text-center"
                        >
                            <div style={{
                                width: 64, height: 64, borderRadius: '50%', background: 'rgba(16, 185, 129, 0.1)',
                                display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent-emerald)'
                            }}>
                                <Check size={32} />
                            </div>
                            <h4 style={{ fontSize: 'var(--font-lg)', fontWeight: 700, color: 'var(--text-primary)' }}>
                                Tümü Eklendi!
                            </h4>
                        </motion.div>
                    )}
                </AnimatePresence>

                {/* Draft Cards */}
                <AnimatePresence>
                    {!isComplete && activeDrafts.length > 0 && (
                        <motion.div
                            className="magic-draft-cards"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                        >
                            <div className="text-xs font-semibold text-muted" style={{
                                textTransform: 'uppercase',
                                letterSpacing: '0.05em',
                                marginBottom: 'var(--space-sm)',
                            }}>
                                {t('magicDraft.parsedExpenses')} ({activeDrafts.length})
                            </div>

                            {activeDrafts.map(draft => (
                                <DraftCard
                                    key={draft._draftId}
                                    draft={draft}
                                    state={state}
                                    t={t}
                                    onUpdate={updateDraft}
                                    onGroupChange={handleGroupChange}
                                    onSave={handleSave}
                                    isSaving={savingId === draft._draftId}
                                />
                            ))}
                        </motion.div>
                    )}
                </AnimatePresence>
            </motion.div>
        </div>
    );
}

// ─── Draft Card Sub-component ───
function DraftCard({ draft, state, t, onUpdate, onGroupChange, onSave, isSaving }) {

    const selectedGroup = state.groups.find(g => g.id === draft.groupId);
    const groupMembers = selectedGroup
        ? selectedGroup.members.map(id => state.members[id]).filter(Boolean)
        : [];

    const isGroupValid = draft.expenseType !== 'group' || draft.groupId;

    return (
        <motion.div
            className={`magic-draft-card ${draft.saved ? 'saved' : ''}`}
            layout
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: draft.saved ? 0 : 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, x: 100, scale: 0.9 }}
            transition={{ duration: 0.3 }}
        >
            {/* Tutar + Başlık */}
            <div className="flex gap-md" style={{ marginBottom: 'var(--space-md)' }}>
                <div style={{ flex: '0 0 140px' }}>
                    <label className="form-label" style={{ fontSize: '0.65rem', marginBottom: 2 }}>
                        {t('magicDraft.amount')}
                    </label>
                    <div className="flex gap-xs">
                        <input
                            type="number"
                            className="form-input"
                            value={draft.amount}
                            onChange={e => onUpdate(draft._draftId, 'amount', e.target.value)}
                            min="0"
                            step="0.01"
                            style={{
                                fontWeight: 700,
                                fontSize: 'var(--font-md)',
                                padding: 'var(--space-sm)',
                                minHeight: 40,
                                width: '100%'
                            }}
                        />
                        <select
                            className="form-select"
                            value={draft.currency}
                            onChange={e => onUpdate(draft._draftId, 'currency', e.target.value)}
                            style={{
                                padding: '0 6px',
                                minHeight: 40,
                                width: 'auto',
                                fontWeight: 600,
                                fontSize: 'var(--font-sm)'
                            }}
                        >
                            <option value="TRY">₺</option>
                            <option value="USD">$</option>
                            <option value="EUR">€</option>
                            <option value="GBP">£</option>
                        </select>
                    </div>
                </div>
                <div style={{ flex: 1 }}>
                    <label className="form-label" style={{ fontSize: '0.65rem', marginBottom: 2 }}>
                        {t('magicDraft.expenseTitle')}
                    </label>
                    <input
                        type="text"
                        className="form-input"
                        value={draft.title}
                        onChange={e => onUpdate(draft._draftId, 'title', e.target.value)}
                        style={{ padding: 'var(--space-sm)', minHeight: 40 }}
                    />
                </div>
            </div>

            {/* Kategori Chips */}
            <div style={{ marginBottom: 'var(--space-md)' }}>
                <label className="form-label" style={{ fontSize: '0.65rem', marginBottom: 4 }}>
                    {t('magicDraft.category')}
                </label>
                <div className="flex flex-wrap gap-xs">
                    {AI_CATEGORIES.map(cat => (
                        <button
                            key={cat}
                            type="button"
                            className={`btn btn-sm ${draft.category === cat ? 'btn-primary' : 'btn-secondary'}`}
                            onClick={() => onUpdate(draft._draftId, 'category', cat)}
                            style={{ fontSize: '0.75rem', padding: '4px 10px', minHeight: 30 }}
                        >
                            {CATEGORY_ICONS[cat]} {cat}
                        </button>
                    ))}
                </div>
            </div>

            {/* Tarih */}
            <div style={{ marginBottom: 'var(--space-md)' }}>
                <label className="form-label" style={{ fontSize: '0.65rem', marginBottom: 2 }}>
                    {t('magicDraft.date')}
                </label>
                <input
                    type="date"
                    className="form-input"
                    value={draft.date}
                    onChange={e => onUpdate(draft._draftId, 'date', e.target.value)}
                    style={{ padding: 'var(--space-sm)', minHeight: 40 }}
                />
            </div>

            {/* Masraf Tipi Toggle */}
            <div style={{ marginBottom: 'var(--space-md)' }}>
                <label className="form-label" style={{ fontSize: '0.65rem', marginBottom: 4 }}>
                    {t('magicDraft.expenseType')}
                </label>
                <div className="flex gap-sm">
                    <button
                        type="button"
                        className={`btn btn-sm flex items-center gap-xs ${draft.expenseType === 'personal' ? 'btn-primary' : 'btn-secondary'}`}
                        onClick={() => onUpdate(draft._draftId, 'expenseType', 'personal')}
                        style={{ flex: 1, minHeight: 38 }}
                    >
                        <User size={14} /> {t('magicDraft.personal')}
                    </button>
                    <button
                        type="button"
                        className={`btn btn-sm flex items-center gap-xs ${draft.expenseType === 'group' ? 'btn-primary' : 'btn-secondary'}`}
                        onClick={() => onUpdate(draft._draftId, 'expenseType', 'group')}
                        style={{ flex: 1, minHeight: 38 }}
                    >
                        <Users size={14} /> {t('magicDraft.group')}
                    </button>
                </div>
            </div>

            {/* Grup seçimi (sadece Grup seçiliyken) */}
            <AnimatePresence>
                {draft.expenseType === 'group' && (
                    <motion.div
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        style={{ marginBottom: 'var(--space-md)' }}
                    >
                        <label className="form-label" style={{ fontSize: '0.65rem', marginBottom: 4 }}>
                            {t('magicDraft.selectGroup')}
                        </label>
                        <select
                            className="form-select"
                            value={draft.groupId}
                            onChange={e => {
                                onGroupChange(draft._draftId, e.target.value);
                            }}
                            style={{
                                minHeight: 40,
                                padding: 'var(--space-sm) var(--space-md)',
                                border: !draft.groupId ? '1px solid var(--accent-amber)' : '1px solid var(--border-primary)',
                            }}
                        >
                            <option value="">{t('magicDraft.chooseGroup')}</option>
                            {state.groups.map(g => (
                                <option key={g.id} value={g.id}>
                                    {g.name} ({g.members.length} {t('magicDraft.members')})
                                </option>
                            ))}
                        </select>

                        {/* Kim Ödedi — sadece grup seçildiyse */}
                        {draft.groupId && groupMembers.length > 0 && (
                            <div style={{ marginTop: 'var(--space-sm)' }}>
                                <label className="form-label" style={{ fontSize: '0.65rem', marginBottom: 4 }}>
                                    {t('magicDraft.paidBy')}
                                </label>
                                <select
                                    className="form-select"
                                    value={draft.paidBy}
                                    onChange={e => onUpdate(draft._draftId, 'paidBy', e.target.value)}
                                    style={{ minHeight: 40, padding: 'var(--space-sm) var(--space-md)' }}
                                >
                                    {groupMembers.map(m => (
                                        <option key={m.id} value={m.id}>
                                            {m.name} {m.isGhost ? '(👻)' : ''}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        )}
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Onayla Butonu */}
            <button
                className="btn btn-success w-full"
                onClick={() => onSave(draft)}
                disabled={isSaving || !draft.amount || !draft.title.trim() || !isGroupValid}
                style={{ borderRadius: 'var(--radius-md)', minHeight: 42 }}
            >
                {isSaving ? (
                    <span className="flex items-center gap-sm">
                        <Loader2 size={16} className="magic-draft-spinner" />
                        {t('magicDraft.saving')}
                    </span>
                ) : (
                    <span className="flex items-center gap-sm">
                        <Check size={16} />
                        {t('magicDraft.confirmSave')}
                    </span>
                )}
            </button>
        </motion.div>
    );
}

