import { useEffect, useRef, useMemo } from 'react';
import { useApp } from '../context/AppContext';
import { formatCurrency } from '../utils/currencyUtils';
import { getInitials, CATEGORIES } from '../utils/helpers';
import { formatDistanceToNow } from 'date-fns';
import { tr, enUS } from 'date-fns/locale';
import { Receipt, HandCoins, Info } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

export default function NotificationMenu({ onClose, isMobile }) {
    const { t, i18n } = useTranslation();
    const { state } = useApp();
    const menuRef = useRef();
    const navigate = useNavigate();

    // Close on click outside
    useEffect(() => {
        function handleClickOutside(event) {
            if (menuRef.current && !menuRef.current.contains(event.target)) {
                onClose();
            }
        }
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [onClose]);

    // Aggregate data
    const notifications = useMemo(() => {
        if (!state.currentUser) return [];

        const activities = [];

        // Add Expenses
        state.expenses.forEach(exp => {
            const group = state.groups.find(g => g.id === exp.groupId);
            if (!group) return;

            const payer = state.members[exp.paidBy];
            const isMePayer = exp.paidBy === state.currentUser;
            const amIInvolved = exp.splitAmong.includes(state.currentUser);

            // Basic filtering if we want to show everything or just involved
            if (group.members.includes(state.currentUser)) {
                activities.push({
                    id: `exp_${exp.id}`,
                    type: 'expense',
                    date: new Date(exp.date),
                    groupId: exp.groupId,
                    groupName: group.name,
                    title: isMePayer
                        ? t('dashboard.notifications.expenseAddedMe', { description: exp.description })
                        : t('dashboard.notifications.expenseAddedOther', { name: payer?.name?.split(' ')[0] || t('common.someone'), description: exp.description }),
                    amount: exp.amount,
                    currency: exp.currency,
                    categoryId: exp.category,
                    icon: Receipt,
                    color: 'var(--accent-purple)'
                });
            }
        });

        // Add Settlements
        state.settlements.forEach(set => {
            const group = state.groups.find(g => g.id === set.groupId);
            if (!group) return;

            const fromUser = state.members[set.from];
            const toUser = state.members[set.to];
            const isMeFrom = set.from === state.currentUser;
            const isMeTo = set.to === state.currentUser;

            let title = '';
            let show = false;

            if (set.status === 'paid') {
                if (isMeFrom) {
                    title = t('dashboard.notifications.settlementPaidMe', { name: toUser?.name?.split(' ')[0] || t('common.someone') });
                    show = true;
                } else if (isMeTo) {
                    title = t('dashboard.notifications.settlementReceivedMe', { name: fromUser?.name?.split(' ')[0] || t('common.someone') });
                    show = true;
                } else {
                    title = t('dashboard.notifications.settlementOther', { from: fromUser?.name?.split(' ')[0], to: toUser?.name?.split(' ')[0] });
                    show = true;
                }
            }

            if (show) {
                activities.push({
                    id: `set_${set.id}`,
                    type: 'settlement',
                    date: new Date(set.paidAt || set.createdAt),
                    groupId: set.groupId,
                    groupName: group.name,
                    title,
                    amount: set.amount,
                    currency: set.currency,
                    icon: HandCoins,
                    color: 'var(--accent-emerald)'
                });
            }
        });

        // Sort latest first
        return activities.sort((a, b) => b.date - a.date).slice(0, 15);
    }, [state.expenses, state.settlements, state.currentUser, state.groups, state.members]);

    const handleNavigate = (groupId) => {
        navigate(`/group/${groupId}`);
        onClose();
    };

    return (
        <div ref={menuRef} style={{
            position: 'absolute',
            top: isMobile ? '56px' : '40px',
            right: isMobile ? '0' : '-80px',
            width: '320px',
            maxHeight: '400px',
            backgroundColor: 'var(--bg-primary)',
            borderRadius: 'var(--radius-lg)',
            boxShadow: '0 10px 40px rgba(0, 0, 0, 0.2)',
            border: '1px solid var(--border-primary)',
            display: 'flex',
            flexDirection: 'column',
            overflow: 'hidden',
            zIndex: 1000,
            animation: 'slideUp 0.2s ease-out'
        }}>
            <div style={{
                padding: 'var(--space-md)',
                borderBottom: '1px solid var(--border-primary)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                background: 'var(--gradient-card)'
            }}>
                <h4 style={{ margin: 0, fontSize: 'var(--font-md)' }}>{t('dashboard.notifications.title')}</h4>
                <div className="badge badge-purple">{t('dashboard.notifications.new', { count: notifications.length })}</div>
            </div>

            <div style={{ overflowY: 'auto', flex: 1 }}>
                {notifications.length === 0 ? (
                    <div style={{ padding: 'var(--space-xl)', textAlign: 'center', color: 'var(--text-muted)' }}>
                        <Info size={24} style={{ margin: '0 auto var(--space-sm)' }} />
                        <p style={{ fontSize: 'var(--font-sm)' }}>{t('dashboard.noNotifications')}</p>
                    </div>
                ) : (
                    <div style={{ display: 'flex', flexDirection: 'column' }}>
                        {notifications.map(notif => {
                            const Icon = notif.icon;
                            return (
                                <div
                                    key={notif.id}
                                    onClick={() => handleNavigate(notif.groupId)}
                                    style={{
                                        padding: 'var(--space-md)',
                                        borderBottom: '1px solid var(--border-primary)',
                                        display: 'flex',
                                        gap: 'var(--space-sm)',
                                        cursor: 'pointer',
                                        transition: 'background var(--transition-fast)'
                                    }}
                                    onMouseEnter={(e) => e.currentTarget.style.backgroundColor = 'var(--bg-glass-hover)'}
                                    onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                                >
                                    <div style={{
                                        width: 36, height: 36, borderRadius: '50%',
                                        backgroundColor: 'var(--bg-secondary)',
                                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                                        color: notif.color,
                                        flexShrink: 0
                                    }}>
                                        <Icon size={18} />
                                    </div>
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <p style={{ margin: 0, fontSize: '0.85rem', fontWeight: 500, color: 'var(--text-primary)', lineHeight: 1.3 }}>
                                            {notif.title}
                                        </p>
                                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 4 }}>
                                            <span style={{ fontSize: '0.7rem', color: 'var(--text-tertiary)' }}>
                                                {formatDistanceToNow(notif.date, { addSuffix: true, locale: i18n.language === 'tr' ? tr : enUS })}
                                            </span>
                                            <span style={{ fontSize: '0.8rem', fontWeight: 700, color: notif.color }}>
                                                {formatCurrency(notif.amount, notif.currency)}
                                            </span>
                                        </div>
                                        <span style={{ fontSize: '0.65rem', color: 'var(--text-muted)', display: 'block', marginTop: 2 }}>
                                            📍 {notif.groupName}
                                        </span>
                                    </div>
                                </div>
                            )
                        })}
                    </div>
                )}
            </div>

            <div style={{
                padding: 'var(--space-sm)',
                textAlign: 'center',
                borderTop: '1px solid var(--border-primary)',
                background: 'var(--bg-secondary)',
                fontSize: '0.75rem',
                color: 'var(--text-muted)'
            }}>
                {t('dashboard.notifications.footer')}
            </div>
        </div>
    );
}

import { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { MessageCircle, Mail, Send, BellDot, X, Star } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { formatCurrency } from '../utils/currencyUtils';
import ProUpgradeModal from './ProUpgradeModal';

export default function NudgeButton({ memberId, amount, groupName, currency }) {
    const { state } = useApp();
    const member = state.members[memberId];
    if (!member) return null;

    const isPro = state.members[state.currentUser]?.isPro;
    const [showOptions, setShowOptions] = useState(false);
    const [dropdownPos, setDropdownPos] = useState({ top: 0, left: 0, width: 0 });
    const [isShaking, setIsShaking] = useState(false);
    const menuRef = useRef();
    const btnRef = useRef();

    useEffect(() => {
        if (isShaking) {
            const timer = setTimeout(() => setIsShaking(false), 500);
            return () => clearTimeout(timer);
        }
    }, [isShaking]);

    useEffect(() => {
        function handleClickOutside(event) {
            if (
                menuRef.current && !menuRef.current.contains(event.target) &&
                btnRef.current && !btnRef.current.contains(event.target)
            ) {
                setShowOptions(false);
            }
        }

        function updatePosition() {
            if (showOptions && btnRef.current) {
                const rect = btnRef.current.getBoundingClientRect();
                setDropdownPos({
                    bottom: window.innerHeight - rect.top + 8, // 8px spacing
                    left: rect.left,
                    width: Math.max(rect.width, 240)
                });
            }
        }

        if (showOptions) {
            updatePosition();
            document.addEventListener('mousedown', handleClickOutside);
            document.addEventListener('touchstart', handleClickOutside, { passive: true });
            window.addEventListener('scroll', updatePosition, true);
            window.addEventListener('resize', updatePosition);
        }
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
            document.removeEventListener('touchstart', handleClickOutside);
            window.removeEventListener('scroll', updatePosition, true);
            window.removeEventListener('resize', updatePosition);
        };
    }, [showOptions]);

    const message = `Merhaba ${member.name.split(' ')[0]},\n\n"${groupName}" grubunda toplam ${formatCurrency(Math.abs(amount), currency)} ödenmemiş borcun bulunuyor. Müsait olduğunda kontrol edebilir misin?\n\n(CoBill ile gönderildi)`;

    const handleWhatsApp = () => {
        const url = `https://wa.me/?text=${encodeURIComponent(message)}`;
        window.open(url, '_blank');
        setShowOptions(false);
    };

    const handleEmail = () => {
        const subject = `CoBill - ${groupName} Borç Hatırlatması`;
        const url = `mailto:${member.email || ''}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(message)}`;
        window.open(url);
        setShowOptions(false);
    };

    const handleCopy = async () => {
        try {
            await navigator.clipboard.writeText(message);
            alert('Mesaj panoya kopyalandı!');
        } catch {
            // Fallback
            const ta = document.createElement('textarea');
            ta.value = message;
            document.body.appendChild(ta);
            ta.select();
            document.execCommand('copy');
            document.body.removeChild(ta);
            alert('Mesaj panoya kopyalandı!');
        }
        setShowOptions(false);
    };

    const handleActionClick = (e) => {
        e.stopPropagation();
        e.preventDefault();

        if (!isPro) {
            setIsShaking(true);
            window.dispatchEvent(new CustomEvent('show-pro-banner'));
        } else {
            setShowOptions(prev => !prev);
        }
    };

    return (
        <div className="flex flex-col gap-sm w-full relative">
            <button
                ref={btnRef}
                className={`btn w-full flex justify-center items-center ${isPro ? 'btn-pro-active' : 'btn-pro-gold'} ${isShaking ? 'shake-animation' : ''}`}
                onClick={handleActionClick}
                style={{ padding: '8px 12px', height: 'auto', fontSize: '0.85rem', fontWeight: 600, borderRadius: 'var(--radius-md)', whiteSpace: 'nowrap' }}
            >
                <BellDot size={14} style={{ marginRight: 6 }} /> Hatırlat
            </button>

            {showOptions && isPro && createPortal(
                <div ref={menuRef} style={{
                    width: dropdownPos.width,
                    minWidth: '240px',
                    backgroundColor: 'var(--bg-card)',
                    backdropFilter: 'blur(16px)',
                    WebkitBackdropFilter: 'blur(16px)',
                    borderRadius: 'var(--radius-lg)',
                    border: '1px solid var(--border-primary)',
                    padding: 'var(--space-md)',
                    boxShadow: '0 10px 40px rgba(0, 0, 0, 0.15)',
                    animation: 'slideUp 0.2s ease-out',
                    zIndex: 9999,
                    position: 'fixed',
                    bottom: dropdownPos.bottom,
                    left: dropdownPos.left,
                }}>
                    <div className="flex justify-between items-center mb-md border-b" style={{ borderColor: 'var(--border-primary)', paddingBottom: 'var(--space-sm)' }}>
                        <h4 className="flex items-center gap-xs m-0 text-sm" style={{ color: 'var(--text-primary)' }}>
                            <Star size={14} fill="var(--accent-amber)" color="var(--accent-amber)" />
                            Hatırlatıcı Gönder
                        </h4>
                        <button className="btn btn-ghost btn-icon p-0 w-6 h-6 text-muted" onClick={() => setShowOptions(false)}><X size={14} /></button>
                    </div>
                    <div className="flex flex-col gap-sm">
                        <button className="btn btn-secondary w-full flex justify-start items-center gap-md text-sm py-2" onClick={() => { handleWhatsApp(); setShowOptions(false); }}>
                            <MessageCircle size={16} style={{ color: '#25D366' }} /> WhatsApp
                        </button>
                        <button className="btn btn-secondary w-full flex justify-start items-center gap-md text-sm py-2" onClick={() => { handleEmail(); setShowOptions(false); }}>
                            <Mail size={16} style={{ color: 'var(--accent-purple)' }} /> E-posta
                        </button>
                        <button className="btn btn-secondary w-full flex justify-start items-center gap-md text-sm py-2" onClick={() => { handleCopy(); setShowOptions(false); }}>
                            <Send size={16} style={{ color: 'var(--text-secondary)' }} /> Kopyala
                        </button>
                    </div>
                </div>,
                document.body
            )}

            <style>{`
                @keyframes shake {
                    0%, 100% { transform: translateX(0); }
                    25% { transform: translateX(-4px); }
                    75% { transform: translateX(4px); }
                }
                .shake-animation {
                    animation: shake 0.2s ease-in-out infinite;
                }
            `}</style>
        </div>
    );
}

// UI Refactored to Modal

import React, { useState } from 'react';
import { CalendarClock, X, CopyMinus, CheckCircle2 } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { useApp } from '../context/AppContext';
import { addOneMonthSafely } from '../utils/recurringUtils';
import { formatCurrency } from '../utils/currencyUtils';

export default function RecurringPromptModal({ pendingExpenses, onClose }) {
    const { t } = useTranslation();
    const { dispatch } = useApp();
    const [isSaving, setIsSaving] = useState(false);
    const [success, setSuccess] = useState(false);

    // Combine group and personal expenses, but process them according to their type
    const handleSkip = async () => {
        setIsSaving(true);
        try {
            await Promise.all(pendingExpenses.map(async (expense) => {
                const nextDate = addOneMonthSafely(expense.nextRecurringDate);
                const updatedExpense = { ...expense, nextRecurringDate: nextDate };

                if (expense.userId) { // Personal expense
                    await dispatch({ type: 'UPDATE_PERSONAL_EXPENSE', payload: updatedExpense });
                } else if (expense.groupId) { // Group expense
                    await dispatch({ type: 'UPDATE_EXPENSE', payload: updatedExpense });
                }
            }));

            setSuccess(true);
            setTimeout(onClose, 1500);
        } catch (error) {
            console.error("Skip failed", error);
            setIsSaving(false);
        }
    };

    const handleAdd = async () => {
        setIsSaving(true);
        try {
            await Promise.all(pendingExpenses.map(async (expense) => {
                // 1. Update the original template's next date
                const nextDate = addOneMonthSafely(expense.nextRecurringDate);
                const updatedExpense = { ...expense, nextRecurringDate: nextDate };

                // 2. Create the new clone to be inserted today
                const { id, nextRecurringDate: _removed, ...cloneData } = expense;

                // Set the duplicate's properties
                // They should be registered as today/the specific recurring date:
                const clone = {
                    ...cloneData,
                    id: crypto.randomUUID ? crypto.randomUUID() : `rect-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
                    date: expense.nextRecurringDate + "T12:00:00.000Z", // Append fake time just to ensure correct ISO parse
                    isRecurring: false,
                };

                if (expense.userId) {
                    await dispatch({ type: 'UPDATE_PERSONAL_EXPENSE', payload: updatedExpense });
                    await dispatch({ type: 'ADD_PERSONAL_EXPENSE', payload: clone });
                } else if (expense.groupId) {
                    await dispatch({ type: 'UPDATE_EXPENSE', payload: updatedExpense });
                    await dispatch({ type: 'ADD_EXPENSE', payload: clone });
                }
            }));

            setSuccess(true);
            setTimeout(onClose, 1500);
        } catch (error) {
            console.error("Add failed", error);
            setIsSaving(false);
        }
    };

    if (success) {
        return (
            <div className="modal-overlay animate-fade-in" style={{ zIndex: 9999 }}>
                <div className="modal-content text-center flex flex-col items-center justify-center gap-md" style={{ maxWidth: 360, padding: 'var(--space-3xl) var(--space-xl)' }}>
                    <CheckCircle2 size={48} style={{ color: 'var(--accent-emerald)' }} className="animate-fade-in-up" />
                    <h3 className="animate-fade-in-up" style={{ animationDelay: '100ms' }}>{t('dashboard.successfullyCompleted')}</h3>
                </div>
            </div>
        );
    }

    return (
        <div className="modal-overlay animate-fade-in" style={{ zIndex: 9999 }}>
            <div className="modal-content" onClick={e => e.stopPropagation()} style={{ maxWidth: 440 }}>
                <div className="modal-header mb-md">
                    <h3 className="flex items-center gap-xs" style={{ color: 'var(--accent-amber)' }}>
                        <CalendarClock size={20} />
                        {t('dashboard.recurring.title')}
                    </h3>
                    <button className="btn btn-ghost btn-icon" onClick={onClose} disabled={isSaving}>
                        <X size={18} />
                    </button>
                </div>

                <p className="text-sm text-secondary mb-xl">
                    {t('dashboard.recurring.desc')}
                </p>

                <div className="flex flex-col gap-sm mb-2xl" style={{ maxHeight: '40vh', overflowY: 'auto' }}>
                    {pendingExpenses.map(e => (
                        <div key={e.id} className="glass-card flex items-center justify-between" style={{ padding: 'var(--space-md) var(--space-lg)' }}>
                            <div className="flex flex-col">
                                <span className="font-semibold text-sm">{e.title || e.description}</span>
                                <span className="text-xs text-muted">{e.category} {e.groupId ? t('dashboard.recurring.group') : t('dashboard.recurring.personal')}</span>
                            </div>
                            <div className="font-bold">
                                {formatCurrency(e.amount, e.currency || 'TRY')}
                            </div>
                        </div>
                    ))}
                </div>

                <div className="flex gap-md mt-auto">
                    <button
                        className="btn btn-secondary flex-1"
                        onClick={handleSkip}
                        disabled={isSaving}
                    >
                        {t('dashboard.recurring.skipMonth')}
                    </button>
                    <button
                        className="btn btn-primary flex-1"
                        onClick={handleAdd}
                        disabled={isSaving}
                    >
                        {isSaving ? t('dashboard.waiting') : t('dashboard.recurring.addNow')}
                    </button>
                </div>
            </div>
        </div>
    );
}

