                    margin: '0 auto var(--space-lg)', display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>
                    <FileText size={26} color="white" />
                </div>

                <h3 style={{ fontSize: '1.2rem', fontWeight: 800, marginBottom: 'var(--space-xs)', color: 'var(--text-primary)' }}>
                    {t('reports.discoverPro')}
                </h3>
                <p style={{ color: 'var(--text-secondary)', fontSize: '0.88rem', lineHeight: 1.6, maxWidth: 320, margin: '0 auto var(--space-xl)' }}>
                    {t('reports.discoverProDesc')}
                </p>

                <button
                    className="btn btn-primary"
                    style={{
                        background: 'var(--gradient-primary)', border: 'none', fontWeight: 700,
                        padding: '12px 32px', fontSize: '0.95rem', borderRadius: 'var(--radius-lg)',
                        boxShadow: '0 4px 20px rgba(139, 92, 246, 0.35)', transition: 'transform 0.2s, box-shadow 0.2s',
                    }}
                    onClick={() => setShowProModal(true)}
                >
                    <Star size={16} fill="currentColor" style={{ marginRight: 6 }} /> {t('reports.upgradeToPro')}
                </button>
            </div>

            {/* Feature List */}
            <div className="flex flex-col gap-md">
                {features.map((f, i) => (
                    <div key={i} className="glass-card flex items-center gap-lg animate-fade-in-up" style={{
                        padding: 'var(--space-md) var(--space-lg)',
                        animationDelay: `${i * 80}ms`,
                    }}>
                        <div style={{
                            width: 40, height: 40, borderRadius: '12px',
                            background: `${f.color}15`, color: f.color,
                            display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
                        }}>
                            {f.icon}
                        </div>
                        <div style={{ flex: 1 }}>
                            <div style={{ fontWeight: 700, fontSize: '0.88rem', marginBottom: 2 }}>{f.title}</div>
                            <div style={{ fontSize: '0.78rem', color: 'var(--text-tertiary)', lineHeight: 1.4 }}>{f.desc}</div>
                        </div>
                        <Lock size={14} style={{ color: 'var(--text-muted)', flexShrink: 0, opacity: 0.4 }} />
                    </div>
                ))}
            </div>
        </div>
    );
}

import { useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { AVATARS } from '../../utils/helpers';

/**
 * AvatarPicker — Premium PNG Avatar Picker
 * @param {number} selectedId - Currently selected avatar ID (1-5).
 * @param {(id: number) => void} onSelect - Callback when user picks a new avatar.
 * @param {string} userName - User name displayed under the avatar.
 * @param {string} subtitle - Subtitle text (e.g. "Avatarını seç").
 */
const AvatarPicker = ({ selectedId = 1, onSelect, userName = '', subtitle = '' }) => {
    const [rotationCount, setRotationCount] = useState(0);

    const selectedAvatar = AVATARS.find(a => a.id === selectedId) || AVATARS[0];

    const handleSelect = (avatar) => {
        if (avatar.id === selectedId) return;
        setRotationCount(prev => prev + 360);
        onSelect?.(avatar.id);
    };

    return (
        <div className="avatar-picker">
            {/* Main avatar display */}
            <motion.div
                className="avatar-picker__main"
                initial={{ y: 20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ type: 'spring', stiffness: 200, damping: 20 }}
            >
                <motion.div
                    className="avatar-picker__main-rotate"
                    animate={{ rotate: rotationCount }}
                    transition={{ duration: 0.6, ease: [0.4, 0, 0.2, 1] }}
                >
                    <div className="avatar-picker__main-inner">
                        <img
                            src={selectedAvatar.src}
                            alt={selectedAvatar.name}
                            style={{
                                width: '100%',
                                height: '100%',
                                borderRadius: '50%',
                                objectFit: 'contain',
                                padding: '12px'
                            }}
                        />
                    </div>
                </motion.div>
            </motion.div>

            {/* Name + subtitle */}
            {(userName || subtitle) && (
                <div className="avatar-picker__info">
                    {userName && <h2 className="avatar-picker__name">{userName}</h2>}
                    {subtitle && <p className="avatar-picker__subtitle">{subtitle}</p>}
                </div>
            )}

            {/* Avatar options */}
            <motion.div
                className="avatar-picker__options"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.3 }}
            >
                {AVATARS.map((avatar) => (
                    <motion.button
                        key={avatar.id}
                        className={`avatar-picker__option ${selectedId === avatar.id ? 'active' : ''}`}
                        onClick={() => handleSelect(avatar)}
                        whileHover={{ y: -2 }}
                        whileTap={{ scale: 0.9 }}
                        style={{
                            opacity: selectedId === avatar.id ? 1 : 0.55,
                            transform: selectedId === avatar.id ? 'scale(1.05)' : 'scale(0.9)',
                            transition: 'opacity 0.3s ease, transform 0.3s ease'
                        }}
                    >
                        <div className="avatar-picker__option-svg" style={{ overflow: 'hidden', borderRadius: '50%' }}>
                            <img
                                src={avatar.src}
                                alt={avatar.name}
                                style={{
                                    width: '100%',
                                    height: '100%',
                                    borderRadius: '50%',
                                    objectFit: 'contain',
                                    padding: '4px'
                                }}
                            />
                        </div>
                        <AnimatePresence>
                            {selectedId === avatar.id && (
                                <motion.div
                                    className="avatar-picker__option-ring"
                                    initial={{ opacity: 0, scale: 0.5 }}
                                    animate={{ opacity: 1, scale: 1 }}
                                    exit={{ opacity: 0, scale: 0.5 }}
                                    transition={{ type: 'spring', stiffness: 300, damping: 20 }}
                                />
                            )}
                        </AnimatePresence>
                    </motion.button>
                ))}
            </motion.div>
        </div>
    );
};

/** Helper: get avatar image src by ID */
export const getAvatarSvg = (avatarId) => {
    const avatar = AVATARS.find(a => a.id === avatarId);
    return avatar ? avatar.src : `${import.meta.env.BASE_URL}avatars/avatar-1.png`;
};

export { AvatarPicker, AVATARS as avatars };
export default AvatarPicker;

import React, { useState, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Plus } from "lucide-react";

const FloatingActionMenu = ({ options, className = "" }) => {
