                                gap: '10px',
                                zIndex: 200,
                                width: '220px',
                            }}
                        >
                            {options.map((option, index) => (
                                <motion.button
                                    key={index}
                                    initial={{ opacity: 0, y: 16 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    exit={{ opacity: 0, y: 16 }}
                                    transition={{
                                        duration: 0.25,
                                        delay: (options.length - 1 - index) * 0.05,
                                    }}
