                                                    <span className="font-medium">{expense.description}</span>
                                                </div>
                                            </td>
                                            <td><span>{cat.icon} {cat.label}</span></td>
                                            <td>
                                                <div className="flex items-center gap-sm">
                                                    <img src={getAvatarImage(payer?.avatarId || 1)} alt={payer?.name || '?'} className="avatar avatar-sm" style={{ objectFit: 'cover' }} />
                                                    {payer?.name?.split(' ')[0]}
                                                </div>
                                            </td>
                                            <td className="text-muted">{formatShortDate(expense.date)}</td>
                                            <td style={{ textAlign: 'right' }}>
                                                <span className="font-bold">{formatCurrency(expense.amount, expense.currency)}</span>
                                            </td>
                                            <td>
                                                {canDeleteExpense(expense) && (
                                                    <button
                                                        className="btn btn-ghost btn-sm"
                                                        onClick={() => handleDeleteExpense(expense)}
                                                        style={{ color: 'var(--accent-rose)' }}
                                                    >
                                                        <Trash2 size={14} />
                                                    </button>
                                                )}
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>

                    {/* Mobile expense list */}
                    <div className="show-mobile" style={{ display: 'none', flexDirection: 'column', gap: 'var(--space-sm)' }}>
                        {filteredGroupExpenses.map(expense => {
                            const payer = state.members[expense.paidBy];
                            const cat = CATEGORIES[expense.category] || CATEGORIES.other;
                            return (
                                <div key={expense.id} className="flex items-center gap-md" style={{
                                    padding: 'var(--space-md)',
                                    background: 'var(--bg-glass)',
                                    borderRadius: 'var(--radius-md)',
                                }}>
                                    <span style={{ fontSize: '1.2rem' }}>{cat.icon}</span>
                                    <div style={{ flex: 1 }}>
                                        <div className="text-sm font-semibold">{expense.description}</div>
                                        <div className="text-xs text-muted">{payer?.name?.split(' ')[0]} • {formatShortDate(expense.date)}</div>
                                    </div>
                                    <span className="font-bold text-sm">{formatCurrency(expense.amount, expense.currency)}</span>
                                </div>
                            );
                        })}
                    </div>
                    {groupEmptyState}
                </div>

                <div className="glass-card static-card">
                    <h4 className="mb-lg flex items-center gap-sm">📊 {t('groups.perPersonExpense')}</h4>
                    <MemberBalanceChart groupId={groupId} />
                </div>

                <div className="glass-card static-card">
                    <h4 className="mb-lg flex items-center gap-sm">🕐 {t('groups.activityFeed')}</h4>
                    <ActivityFeed groupId={groupId} limit={20} />
                </div>
            </div>

            {/* Modals */}
            {showMembers && (
                <MemberManager groupId={groupId} onClose={() => setShowMembers(false)} />
            )}

            {showExpenseForm && (
                <div className="modal-overlay" onClick={() => setShowExpenseForm(false)}>
                    <div className="modal-content" onClick={e => e.stopPropagation()} style={{ maxWidth: 560 }}>
                        <div className="modal-header">
                            <h3>{t('groups.addExpenseTitle')}</h3>
                            <button className="btn btn-ghost btn-icon" onClick={() => setShowExpenseForm(false)}>✕</button>
                        </div>
                        <ExpenseForm groupId={groupId} onClose={() => setShowExpenseForm(false)} />
                    </div>
                </div>
            )}

            {showProModal && (
                <ProUpgradeModal onClose={() => setShowProModal(false)} />
            )}
        </div>
    );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    PlusCircle, Users, TrendingUp, TrendingDown, Wallet,
    ArrowLeftRight, MailCheck, UserCheck, X, Zap,
    SlidersHorizontal, RotateCcw, CheckCircle
} from 'lucide-react';
import { useApp } from '../context/AppContext';
import GroupCard from '../components/GroupCard';
import ActivityFeed from '../components/ActivityFeed';
import { SpendingByCategory } from '../components/BalanceChart';
import { calculateBalances, getTotalUserDebt } from '../utils/debtSimplification';
import { formatCurrency } from '../utils/currencyUtils';
import DateFilterBar from '../components/DateFilterBar';
import { getDateRange, filterByDateRange } from '../utils/dateFilterUtils';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';

export default function Groups() {
    const { state, dispatch } = useApp();
    const { t } = useTranslation();
    const navigate = useNavigate();
    const [showNew, setShowNew] = useState(false);
    const [name, setName] = useState('');
    const [desc, setDesc] = useState('');
    const [currency, setCurrency] = useState('TRY');
    const [showProModal, setShowProModal] = useState(false);
    const [dateFilter, setDateFilter] = useState(getDateRange('all'));
    const [showFilterModal, setShowFilterModal] = useState(false);
    const isPro = state.members[state.currentUser]?.isPro;

    const colors = ['#8b5cf6', '#06b6d4', '#10b981', '#f59e0b', '#f43f5e', '#3b82f6', '#ec4899'];
    const [color, setColor] = useState(colors[0]);

    // Calculate global stats (from Dashboard)
    let totalOwedToYou = 0;
    let totalYouOwe = getTotalUserDebt(state);
    let totalExpenses = 0;
    let pendingSettlements = 0;

    state.groups.forEach(group => {
        const groupMembers = group.members.map(id => state.members[id]).filter(Boolean);
        const groupExpenses = state.expenses.filter(e => e.groupId === group.id);
        const balances = calculateBalances(groupExpenses, groupMembers);
        const myBalance = balances[state.currentUser] || 0;

        if (myBalance > 0) totalOwedToYou += myBalance;
        totalExpenses += groupExpenses.reduce((s, e) => s + e.amount, 0);
    });

    pendingSettlements = state.settlements.filter(s => s.status !== 'paid').length;

    const stats = [
        {
            icon: <TrendingUp size={22} />,
            iconBg: 'rgba(16, 185, 129, 0.15)',
            iconColor: 'var(--accent-emerald)',
            value: formatCurrency(totalOwedToYou, 'TRY'),
            label: t('dashboard.owedToYou'),
            gradient: 'var(--gradient-success)',
        },
        {
            icon: <TrendingDown size={22} />,
            iconBg: 'rgba(244, 63, 94, 0.15)',
            iconColor: 'var(--accent-rose)',
            value: formatCurrency(totalYouOwe, 'TRY'),
            label: t('dashboard.youOwe'),
            gradient: 'var(--gradient-danger)',
        },
        {
            icon: <Wallet size={22} />,
            iconBg: 'rgba(139, 92, 246, 0.15)',
            iconColor: 'var(--accent-purple)',
            value: formatCurrency(totalExpenses, 'TRY'),
            label: t('dashboard.totalExpense'),
            gradient: 'var(--gradient-primary)',
        },
        {
            icon: <ArrowLeftRight size={22} />,
            iconBg: 'rgba(245, 158, 11, 0.15)',
            iconColor: 'var(--accent-amber)',
            value: pendingSettlements.toString(),
            label: t('dashboard.pendingSettlement'),
            gradient: 'var(--gradient-danger)',
        },
    ];

    const handleCreate = (e) => {
        e.preventDefault();
        if (!name.trim()) return;

        const id = Date.now().toString(36) + Math.random().toString(36).substr(2, 5);
        dispatch({
            type: 'ADD_GROUP',
            payload: {
                id,
                name: name.trim(),
                description: desc.trim(),
                currency,
                members: [state.currentUser],
                createdBy: state.currentUser,
                createdAt: new Date().toISOString(),
                color,
            },
        });
        setShowNew(false);
        setName('');
        setDesc('');
        if (!isPro) {
            showInterstitialAd().then(() => navigate(`/group/${id}`));
        } else {
            navigate(`/group/${id}`);
        }
    };

    return (
        <div style={{ position: 'relative' }}>
            <div className="page-header">
                <div>
                    <h2>
                        {t('dashboard.greeting')} <span className="text-gradient">
                            {state.members[state.currentUser]?.name?.split(' ')[0] || t('common.user')}
                        </span> 👋
                    </h2>
                    <p className="page-subtitle">{t('groups.subtitle')}</p>
                </div>
                <div className="flex gap-sm">
                    <button
                        className="btn btn-secondary"
                        onClick={() => setShowFilterModal(true)}
                        style={{
                            display: 'inline-flex', alignItems: 'center', gap: '6px',
                            minHeight: '36px', fontSize: '0.82rem', borderRadius: 'var(--radius-md)',
                        }}
                    >
                        <SlidersHorizontal size={14} /> {t('groups.filter')}
                        {(dateFilter.startDate || dateFilter.endDate) && (
                            <span style={{
                                background: 'var(--gradient-primary)', color: 'white',
                                fontSize: '10px', fontWeight: 800, width: '18px', height: '18px',
                                borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center',
                                marginLeft: '2px',
                            }}>
                                1
                            </span>
                        )}
                    </button>
                    <button className="btn btn-primary" onClick={() => setShowNew(true)}>
                        <PlusCircle size={16} /> {t('groups.newGroup')}
                    </button>
                </div>
            </div>

            {/* Bekleyen Davetler */}
            {state.invitations && state.invitations.length > 0 && (
                <div className="glass-card mb-xl animate-fade-in-up" style={{ border: '1px solid rgba(245, 158, 11, 0.3)', background: 'var(--bg-card)' }}>
                    <h4 className="flex items-center gap-sm mb-lg" style={{ color: 'var(--accent-amber-light)' }}>
                        <MailCheck size={18} /> {t('dashboard.pendingInvitations')}
                        <span className="badge badge-amber" style={{ marginLeft: 'auto' }}>{state.invitations.length}</span>
                    </h4>
                    <div className="flex flex-col gap-md">
                        {state.invitations.map(inv => (
                            <div key={inv.id} className="flex items-center gap-md" style={{
                                padding: 'var(--space-md) var(--space-lg)',
                                background: 'var(--bg-glass)',
                                borderRadius: 'var(--radius-md)',
                                border: '1px solid var(--border-primary)'
                            }}>
                                <div style={{ flex: 1 }}>
                                    <div className="text-sm font-semibold">
                                        <strong>{inv.invitedByName || t('common.user')}</strong> {t('dashboard.invitedBy')} <strong>"{inv.groupName}"</strong>.
                                    </div>
                                    <div className="text-xs text-muted mt-xs">
                                        {inv.createdAt ? new Date(inv.createdAt).toLocaleDateString('tr-TR') : ''}
                                    </div>
                                </div>
                                <div className="flex gap-sm">
                                    <button
                                        className="btn btn-success btn-sm"
                                        onClick={() => dispatch({
                                            type: 'ACCEPT_INVITATION',
                                            payload: { invitationId: inv.id, invitation: inv }
                                        })}
                                    >
                                        <UserCheck size={14} /> {t('dashboard.accept')}
                                    </button>
                                    <button
                                        className="btn btn-ghost btn-sm"
                                        onClick={() => dispatch({ type: 'REJECT_INVITATION', payload: inv.id })}
                                        style={{ color: 'var(--accent-rose)' }}
                                    >
                                        <X size={14} /> {t('dashboard.reject')}
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Stat Cards */}
            <div className="grid grid-4 mb-xl mobile-scroller">
                {stats.map((stat, i) => (
                    <div key={i} className={`stat-card animate-fade-in-up stagger-${i + 1}`}>
                        <div className="stat-icon" style={{ background: stat.iconBg, color: stat.iconColor }}>
                            {stat.icon}
                        </div>
                        <div className="stat-value" style={{
                            background: stat.gradient,
                            WebkitBackgroundClip: 'text',
                            WebkitTextFillColor: 'transparent',
                            backgroundClip: 'text',
                        }}>
                            {stat.value}
                        </div>
                        <div className="stat-label">{stat.label}</div>
                    </div>
                ))}
            </div>

            {/* Main Grid */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 380px', gap: 'var(--space-xl)', minWidth: 0 }} className="dashboard-grid">

                {/* Left: Groups */}
                <div style={{ minWidth: 0 }}>
                    <div className="flex items-center justify-between mb-lg">
                        <h3>{t('dashboard.yourGroups')}</h3>
                        <span className="badge badge-purple">{state.groups.length}</span>
                    </div>

                    {state.groups.length === 0 ? (
                        <div className="glass-card animate-fade-in-up flex flex-col items-center text-center" style={{ padding: 'var(--space-2xl) var(--space-xl)' }}>
                            <Users size={40} style={{ color: 'var(--text-muted)', marginBottom: 'var(--space-md)', opacity: 0.5 }} />
                            <h4 style={{ marginBottom: 'var(--space-xs)', color: 'var(--text-primary)' }}>{t('dashboard.noGroupsYet')}</h4>
                            <p className="text-sm text-muted" style={{ marginBottom: 'var(--space-lg)', maxWidth: 260 }}>
                                {t('dashboard.createFirstGroup')}
                            </p>
                            <button className="btn btn-primary flex items-center gap-sm" onClick={() => setShowNew(true)}>
                                <PlusCircle size={16} /> {t('dashboard.createNewGroup')}
                            </button>
                        </div>
                    ) : (
                        <div className="grid grid-2 mobile-scroller" style={{ gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', paddingBottom: 'var(--space-lg)' }}>
                            {state.groups.map((group, i) => (
                                <GroupCard key={group.id} group={group} index={i} />
                            ))}

                            {/* Add Group Card */}
                            <div
                                className="glass-card animate-fade-in-up flex items-center justify-center flex-col"
                                style={{
                                    cursor: 'pointer',
                                    minHeight: 180,
                                    border: '2px dashed var(--border-secondary)',
                                    background: 'transparent',
                                }}
                                onClick={() => setShowNew(true)}
                            >
                                <PlusCircle size={32} style={{ color: 'var(--text-muted)', marginBottom: 8 }} />
                                <p className="text-sm text-muted">{t('dashboard.createNewGroup')}</p>
                            </div>
                        </div>
                    )}

                    {/* Inline Promo Ad */}
                    {!isPro && (
                        <div className="glass-card animate-fade-in-up flex flex-col justify-center items-center text-center relative overflow-hidden mt-lg" style={{ padding: 'var(--space-lg)', border: '1px solid rgba(139, 92, 246, 0.2)' }}>
                            <div style={{ position: 'absolute', top: -40, right: -40, width: 90, height: 90, borderRadius: '50%', background: 'var(--gradient-primary)', filter: 'blur(35px)', opacity: 0.5 }}></div>
                            <Zap size={24} style={{ color: 'var(--accent-purple)', marginBottom: 'var(--space-xs)' }} />
                            <h4 style={{ marginBottom: 4, fontSize: '0.9rem' }}>{t('dashboard.adFreeExperience')}</h4>
                            <p className="text-xs text-muted mb-md">{t('dashboard.adFreeDesc')}</p>
                            <button className="btn btn-pro-active" style={{ fontSize: '0.8rem', padding: '6px 12px', minHeight: '36px' }} onClick={() => setShowProModal(true)}>
                                {t('dashboard.checkNow')}
                            </button>
                            <span style={{ position: 'absolute', top: 6, right: 10, fontSize: '9px', background: 'var(--bg-glass)', border: '1px solid var(--border-primary)', padding: '2px 6px', borderRadius: 4, color: 'var(--text-tertiary)', letterSpacing: 0.5 }}>AD</span>
                        </div>
                    )}
                </div>

                {/* Right: Activity + Chart */}
                <div className="flex flex-col gap-xl sidebar-panel" style={{ minWidth: 0 }}>
                    <div className="glass-card" style={{ minWidth: 0 }}>
                        <h4 className="mb-lg" style={{ fontSize: 'var(--font-base)' }}>{t('dashboard.recentActivities')}</h4>
                        <div style={{ width: '100%', overflowX: 'auto' }}>
                            <ActivityFeed limit={8} />
                        </div>
                    </div>

                    {totalExpenses > 0 && (
                        <div className="glass-card" style={{ minWidth: 0 }}>
                            <h4 className="mb-lg" style={{ fontSize: 'var(--font-base)' }}>{t('dashboard.spendingDistribution')}</h4>
                            <div style={{ width: '100%', overflowX: 'auto', WebkitOverflowScrolling: 'touch', paddingBottom: '4px', position: 'relative' }}>
                                <SpendingByCategory dateFilter={dateFilter} />
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Filter Modal */}
            {createPortal(
                <div style={{
                    position: 'fixed', inset: 0, zIndex: 9999,
                    pointerEvents: showFilterModal ? 'auto' : 'none',
                    visibility: showFilterModal ? 'visible' : 'hidden',
                    opacity: showFilterModal ? 1 : 0,
                    transition: 'opacity 200ms ease, visibility 200ms ease',
                }}>
                    <div onClick={() => setShowFilterModal(false)} style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.3)' }} />
                    <div style={{
                        position: 'absolute', bottom: 0, left: 0, right: 0,
                        background: 'var(--bg-secondary)', borderRadius: 'var(--radius-xl) var(--radius-xl) 0 0',
                        padding: 'var(--space-xl)', maxHeight: '75vh', overflowY: 'auto',
                        transform: showFilterModal ? 'translateY(0)' : 'translateY(100%)', transition: 'transform 300ms ease',
                    }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 'var(--space-lg)' }}>
                            <h4 style={{ fontWeight: 700, fontSize: '1.1rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                <SlidersHorizontal size={18} /> {t('groups.filter')}
                            </h4>
                            <div style={{ display: 'flex', gap: '8px' }}>
                                <button className="btn btn-ghost btn-sm" onClick={() => setDateFilter(getDateRange('all'))} style={{ fontSize: '0.75rem', padding: '4px 10px', minHeight: '30px' }}>
                                    <RotateCcw size={12} /> {t('groups.reset')}
                                </button>
                                <button className="btn btn-ghost btn-icon" onClick={() => setShowFilterModal(false)} style={{ width: '30px', height: '30px', minHeight: '30px', padding: 0 }}>
                                    <X size={16} />
                                </button>
                            </div>
                        </div>
                        <div style={{ width: 40, height: 4, borderRadius: 'var(--radius-full)', background: 'var(--border-secondary)', margin: '-12px auto var(--space-lg)' }} />

                        <div style={{ marginBottom: 'var(--space-xl)' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginBottom: 'var(--space-md)', color: 'var(--text-secondary)', fontWeight: 600, fontSize: '0.82rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                                {t('groups.dateSelection')}
                            </div>
                            <DateFilterBar onChange={setDateFilter} defaultPreset="all" />
                        </div>

                        <button className="btn btn-primary w-full" onClick={() => setShowFilterModal(false)} style={{ padding: '12px', fontSize: '1rem', fontWeight: 700, borderRadius: 'var(--radius-lg)', marginTop: 'var(--space-md)' }}>
                            {t('groups.showResults')}
                        </button>
                    </div>
                </div>,
                document.body
            )}

            {/* New Group Modal */}
            {showNew && (
                <div className="modal-overlay" onClick={() => setShowNew(false)}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h3>{t('dashboard.newGroupModalTitle')}</h3>
                            <button className="btn btn-ghost btn-icon" onClick={() => setShowNew(false)}>✕</button>
                        </div>
                        <form onSubmit={handleCreate} className="flex flex-col gap-lg">
                            <div className="form-group">
                                <label className="form-label">{t('dashboard.groupName')}</label>
                                <input className="form-input" placeholder={t('dashboard.groupNamePlaceholder')} value={name}
                                    onChange={e => setName(e.target.value)} required />
                            </div>
                            <div className="form-group">
                                <label className="form-label">{t('dashboard.description')}</label>
                                <input className="form-input" placeholder={t('dashboard.descriptionPlaceholder')} value={desc}
                                    onChange={e => setDesc(e.target.value)} />
                            </div>
                            <div className="form-group">
                                <label className="form-label">{t('dashboard.currency')}</label>
                                <select className="form-select" value={currency} onChange={e => setCurrency(e.target.value)}>
                                    <option value="TRY">₺ TRY</option>
                                    <option value="USD">$ USD</option>
                                    <option value="EUR">€ EUR</option>
                                    <option value="GBP">£ GBP</option>
                                </select>
                            </div>
                            <div className="form-group">
                                <label className="form-label">{t('dashboard.color')}</label>
                                <div className="flex gap-sm">
                                    {colors.map(c => (
                                        <div key={c} onClick={() => setColor(c)} style={{
                                            width: 32, height: 32, borderRadius: 'var(--radius-full)',
                                            background: c, cursor: 'pointer',
                                            border: color === c ? '3px solid white' : '3px solid transparent',
                                        }} />
                                    ))}
                                </div>
                            </div>
                            <button type="submit" className="btn btn-primary w-full btn-lg">
                                <Users size={16} /> {t('common.save')}
                            </button>
                        </form>
                    </div>
                </div>
            )}

            {showProModal && (
                <ProUpgradeModal onClose={() => setShowProModal(false)} />
            )}

            {/* Responsive grid override */}
            <style>{`
        @media (max-width: 767px) {
          .dashboard-grid {
            grid-template-columns: 1fr !important;
            width: 100%;
          }
          .dashboard-grid > div {
            min-width: 0;
            width: 100%;
          }
          .sidebar-panel {
            order: -1;
          }
        }
        @media (min-width: 768px) and (max-width: 1100px) {
          .dashboard-grid {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
        </div>
    );
}

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, signOut } from 'firebase/auth';
import { auth } from '../config/firebase';
import { dbService } from '../utils/dbService';
import { LogIn } from 'lucide-react';
import splashScreenImg from '../../assets/splash.png';
import { useTranslation } from 'react-i18next';

export default function Login() {
    const { t } = useTranslation();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        if ((email.toLowerCase() === 'test' && password === 'test') || (email.toLowerCase() === 'demo' && password === 'demo')) {
            // Tamamen sahte (mock) user objesi yaratarak Firebase'i by-pass ederiz.
            // Bu event listener sadece App.jsx'teki state'i değiştiğinde devreye girer.
            // Bu local mock router işini session storage üstünden de yapabilirsek daha stabil olur.
            // Fakat React state üstünden de hacklenebilir.

            // App.jsx mock user alabilmesi için window objesine hook atıp sayfayı yeniletmek en kısasıdır
            // (Ya da onAuthStateChanged dinleyicisini ezip mocklamak gereklidir).
            const isDemo = email.toLowerCase() === 'demo';
            sessionStorage.setItem('MOCK_FIREBASE_USER', JSON.stringify({
                uid: isDemo ? 'demo-user-id' : 'test-user-id',
                email: isDemo ? 'demo@cobill.local' : 'test@cobill.local',
                displayName: isDemo ? 'Demo Kullanıcısı' : 'Test Kullanıcısı'
            }));
            window.location.reload();
            return;
        }

        try {
            const userCredential = await signInWithEmailAndPassword(auth, email, password);
            const user = userCredential.user;

            if (!user.emailVerified) {
                await signOut(auth);
                const error = new Error(t('auth.emailNotVerified'));
                error.code = 'custom/email-not-verified';
                throw error;
            }

            navigate('/wallet');
        } catch (err) {
            console.error('Login error:', err);
            if (err.code === 'custom/email-not-verified') {
                setError(t('auth.errorVerficationLink'));
            } else {
                setError(t('auth.loginFailed'));
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="flex flex-col items-center justify-center min-h-screen p-lg">
            <div className="glass-card w-full" style={{ maxWidth: 420, padding: 'var(--space-2xl)' }}>
                <div className="flex flex-col items-center mb-xl">
                    <img
                        src={splashScreenImg}
                        alt="CoBill Logo"
                        style={{ width: 250, height: 250, objectFit: 'contain', marginBottom: 'var(--space-md)' }}
                    />
                    <h2 style={{ fontSize: 'var(--font-2xl)', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '4px' }}>{t('auth.loginTitle')}</h2>
                    <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', textAlign: 'center' }}>
                        {t('auth.loginSubtitle')}
                    </p>
                </div>

                {error && (
                    <div className="mb-lg p-md" style={{ background: 'rgba(244, 63, 94, 0.1)', color: 'var(--accent-rose)', borderRadius: 'var(--radius-md)', fontSize: '13px' }}>
                        {error}
                    </div>
                )}

                <form onSubmit={handleLogin} className="flex flex-col gap-md">
                    <div className="form-group">
                        <label>{t('auth.emailLabel')}</label>
                        <input
                            type="text"
                            className="form-input"
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                            placeholder={t('auth.emailPlaceholderLogin')}
                            required
                        />
                    </div>
                    <div className="form-group">
                        <div className="flex justify-between items-center mb-xs">
                            <label style={{ marginBottom: 0 }}>{t('auth.passwordLabel')}</label>
                            <Link to="/forgot-password" style={{ fontSize: '11px', color: 'var(--text-secondary)', textDecoration: 'none' }}>
                                {t('auth.forgotPasswordLink')}
                            </Link>
                        </div>
                        <input
                            type="password"
                            className="form-input"
                            value={password}
                            onChange={e => setPassword(e.target.value)}
                            placeholder="••••••••"
                            required
                        />
                    </div>

                    <button
                        type="submit"
                        className="btn btn-primary w-full mt-lg flex items-center justify-center gap-sm"
                        style={{ background: 'var(--gradient-primary)' }}
                        disabled={loading}
                    >
                        {loading ? t('auth.loggingIn') : <><LogIn size={20} /> {t('auth.loginButton')}</>}
                    </button>
                </form>

                <div className="text-center mt-xl pt-lg" style={{ borderTop: '1px solid var(--border-primary)' }}>
                    <p style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                        {t('auth.noAccount')}{' '}
                        <Link to="/register" style={{ color: 'var(--accent-purple)', fontWeight: 700, textDecoration: 'none' }}>
                            {t('auth.registerNow')}
                        </Link>
                    </p>
                </div>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { useApp } from '../context/AppContext';
import { formatCurrency } from '../utils/currencyUtils';
import { formatDate } from '../utils/helpers';
import { Wallet, Trash2, Calendar } from 'lucide-react';
import ProUpgradeModal from '../components/ProUpgradeModal';
import ExpenseFilterSort from '../components/ExpenseFilterSort';

const PERSONAL_CATEGORIES = {
    Market: { icon: '🛒', label: 'Market', color: 'var(--accent-emerald)' },
    Fatura: { icon: '📋', label: 'Fatura', color: 'var(--accent-cyan)' },
    'Eğitim': { icon: '📚', label: 'Eğitim', color: 'var(--accent-blue)' },
    'Eğlence': { icon: '🎬', label: 'Eğlence', color: 'var(--accent-purple)' },
    'Ulaşım': { icon: '🚕', label: 'Ulaşım', color: 'var(--accent-amber)' },
    'Diğer': { icon: '📦', label: 'Diğer', color: 'var(--text-tertiary)' },
};

import { useTranslation } from 'react-i18next';

export default function PersonalWallet() {
    const { state, dispatch } = useApp();
    const { t } = useTranslation();
    const [showProModal, setShowProModal] = useState(false);
    const isPro = state.members[state.currentUser]?.isPro;

    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();

    // Filter this month's expenses (for the summary card — never changes with filter)
    const thisMonthExpenses = state.personalExpenses.filter(e => {
        const d = new Date(e.date);
        return d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    });

    const totalThisMonth = thisMonthExpenses.reduce((sum, e) => sum + e.amount, 0);

    // Category breakdown for summary bar
    const categoryBreakdown = {};
    thisMonthExpenses.forEach(e => {
        categoryBreakdown[e.category] = (categoryBreakdown[e.category] || 0) + e.amount;
    });

    const handleDelete = (id) => {
        if (window.confirm(t('wallet.deleteConfirm'))) {
            dispatch({ type: 'DELETE_PERSONAL_EXPENSE', payload: id });
        }
    };

    // Define categories inside component to use translations
    const PERSONAL_CATEGORIES = {
        Market: { icon: '🛒', label: t('wallet.categories.market'), color: 'var(--accent-emerald)' },
        Fatura: { icon: '📋', label: t('wallet.categories.bill'), color: 'var(--accent-cyan)' },
        'Eğitim': { icon: '📚', label: t('wallet.categories.education'), color: 'var(--accent-blue)' },
        'Eğlence': { icon: '🎬', label: t('wallet.categories.entertainment'), color: 'var(--accent-purple)' },
        'Ulaşım': { icon: '🚕', label: t('wallet.categories.transport'), color: 'var(--accent-amber)' },
        'Diğer': { icon: '📦', label: t('wallet.categories.other'), color: 'var(--text-tertiary)' },
    };

    // Use ExpenseFilterSort hook
    const { filteredExpenses, filterUI, emptyState } = ExpenseFilterSort({
        expenses: state.personalExpenses,
        categories: PERSONAL_CATEGORIES,
        categoryKey: 'category',
        enableDateFilter: true,
    });

    return (
        <div className="animate-fade-in" style={{ maxWidth: 700, margin: '0 auto' }}>
            <div className="page-header">
                <div>
                    <h2>💳 {t('wallet.title')}</h2>
                    <p className="page-subtitle">{t('wallet.subtitle')}</p>
                </div>
            </div>

            {/* Monthly Summary Card — always shows real total */}
            <div className="glass-card static-card" style={{
                padding: 'var(--space-xl) var(--space-2xl)',
                marginBottom: 'var(--space-xl)',
                position: 'relative', overflow: 'hidden',
                background: 'var(--bg-card)',
            }}>
                <div style={{ position: 'absolute', top: -40, right: -40, width: 120, height: 120, borderRadius: '50%', background: 'rgba(139, 92, 246, 0.08)', filter: 'blur(40px)', pointerEvents: 'none' }} />
                <div className="flex items-center gap-md mb-md" style={{ color: 'var(--text-tertiary)' }}>
                    <Calendar size={16} />
                    <span className="text-sm font-semibold">
                        {now.toLocaleDateString('tr-TR', { month: 'long', year: 'numeric' })}
                    </span>
                </div>
                <div style={{ fontSize: 'var(--font-3xl)', fontWeight: 900, marginBottom: 'var(--space-xs)' }} className="text-gradient">
                    {formatCurrency(totalThisMonth, 'TRY')}
                </div>
                <div className="text-sm text-muted">{t('wallet.totalThisMonth')} {thisMonthExpenses.length} {t('wallet.expenses')}</div>

                {/* Mini category bars */}
                {Object.keys(categoryBreakdown).length > 0 && (
                    <div className="flex gap-xs mt-lg" style={{ height: 6, borderRadius: 'var(--radius-full)', overflow: 'hidden', background: 'var(--bg-glass)' }}>
                        {Object.entries(categoryBreakdown).map(([cat, amount]) => {
                            const pct = totalThisMonth > 0 ? (amount / totalThisMonth * 100) : 0;
                            const catInfo = PERSONAL_CATEGORIES[cat] || PERSONAL_CATEGORIES['Diğer'];
                            return (
                                <div
                                    key={cat}
                                    style={{
                                        width: `${pct}%`,
                                        background: catInfo.color,
                                        borderRadius: 'var(--radius-full)',
                                        transition: 'width 0.5s ease',
                                    }}
                                    title={`${cat}: ${pct.toFixed(0)}%`}
                                />
                            );
                        })}
                    </div>
                )}
            </div>

            {/* Filter Button */}
            <div style={{ marginBottom: 'var(--space-lg)' }}>
                {filterUI}
            </div>

            {/* Expense List */}
            {emptyState ? emptyState : filteredExpenses.length > 0 ? (
                <div className="flex flex-col gap-sm">
                    {filteredExpenses.map((expense, i) => {
                        const catInfo = PERSONAL_CATEGORIES[expense.category] || PERSONAL_CATEGORIES['Diğer'];
                        return (
                            <div
                                key={expense.id}
                                className={`glass-card flex items-center gap-lg animate-fade-in-up stagger-${Math.min(i + 1, 6)}`}
                                style={{ padding: 'var(--space-md) var(--space-lg)' }}
                            >
                                <div style={{
                                    width: 44, height: 44, borderRadius: '14px',
                                    background: `${catInfo.color}15`, color: catInfo.color,
                                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                                    fontSize: '1.2rem', flexShrink: 0,
                                }}>
                                    {catInfo.icon}
                                </div>
                                <div style={{ flex: 1, minWidth: 0 }}>
                                    <div className="font-semibold text-sm truncate">{expense.title}</div>
                                    <div className="text-xs text-muted flex items-center gap-xs">
                                        <span>{PERSONAL_CATEGORIES[expense.category]?.label || t('wallet.categories.other')}</span>
                                        <span>·</span>
                                        <span>{formatDate(expense.date)}</span>
                                    </div>
                                </div>
                                <div style={{ textAlign: 'right', flexShrink: 0 }}>
                                    <div className="font-bold text-sm" style={{ color: 'var(--accent-rose)' }}>
                                        -{formatCurrency(expense.amount, 'TRY')}
                                    </div>
                                </div>
                                <button
                                    className="btn btn-ghost btn-icon"
                                    onClick={() => handleDelete(expense.id)}
                                    style={{ flexShrink: 0, opacity: 0.5 }}
                                >
                                    <Trash2 size={14} />
                                </button>
                            </div>
                        );
                    })}
                </div>
            ) : (
                <div className="empty-state glass-card static-card">
                    <div className="empty-icon">💳</div>
                    <h3>{t('wallet.noExpensesYet')}</h3>
                    <p className="text-sm mb-lg">{t('wallet.addExpenseHint')}</p>
                </div>
            )}

            {showProModal && <ProUpgradeModal onClose={() => setShowProModal(false)} />}
        </div>
    );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    Check, AlertCircle
} from 'lucide-react';
import { useApp } from '../context/AppContext';
import { useTranslation } from 'react-i18next';
import { auth } from '../config/firebase';
import { sendPasswordResetEmail, verifyBeforeUpdateEmail, deleteUser } from 'firebase/auth';
import { dbService } from '../utils/dbService';
import AvatarPicker from '../components/ui/AvatarPicker';
import { createPortal } from 'react-dom';
import { motion, AnimatePresence } from 'framer-motion';

// Sub-components
import IbanCard from '../components/profile/IbanCard';
import AccountSection from '../components/profile/AccountSection';
import NotificationSection from '../components/profile/NotificationSection';
import AppSettingsSection from '../components/profile/AppSettingsSection';
import SecuritySection from '../components/profile/SecuritySection';
import DangerZone from '../components/profile/DangerZone';

export default function Profile() {
    const { state, dispatch } = useApp();
    const { t, i18n } = useTranslation();
    const navigate = useNavigate();
    const currentUser = state.members[state.currentUser];

    // Card/Logic States
    const [toast, setToast] = useState(null);
    const [expanded, setExpanded] = useState(null); // 'account', 'notifications', 'settings', 'security'

    // Form States
    const [accountForm, setAccountForm] = useState({
        email: currentUser?.email || '',
        phone: currentUser?.phone || ''
    });

    // Local state for UI responsiveness
    const pushEnabled = currentUser?.preferences?.pushNotifications ?? true;
    const emailEnabled = currentUser?.preferences?.emailNotifications ?? false;
    const reminderFrequency = state.settings?.reminderFrequency || 'never';
    const theme = state.settings?.theme || 'light';
    const language = i18n.language?.toUpperCase() === 'EN' ? 'EN' : 'TR';

    const showToast = (message, type = 'success') => {
        setToast({ message, type });
        setTimeout(() => setToast(null), 3000);
    };

    const handleToggleNotification = async (type) => {
        const isPush = type === 'push';
        const currentPush = pushEnabled;
        const currentEmail = emailEnabled;

        const newPush = isPush ? !currentPush : currentPush;
        const newEmail = !isPush ? !currentEmail : currentEmail;

        if (isPush && newPush === true) {
            try {
                const { requestAndSaveFCMToken } = await import('../utils/notificationService');
                const token = await requestAndSaveFCMToken();

                dispatch({
                    type: 'UPDATE_MEMBER',
                    payload: { id: state.currentUser, preferences: { pushNotifications: true, emailNotifications: newEmail }, fcmToken: token }
                });
                showToast(t('profile.pushEnabledSuccess'));
                return;
            } catch (error) {
                showToast(error.message === 'NOT_SUPPORTED' ? t('profile.pushNotSupported') : t('profile.pushPermissionDenied'), 'error');
                return;
            }
        }

        dispatch({
            type: 'UPDATE_MEMBER',
            payload: { id: state.currentUser, preferences: { pushNotifications: newPush, emailNotifications: newEmail } }
        });
    };

    const handleSaveAccount = async (e) => {
        e.preventDefault();
        try {
            let emailChanged = false;
            if (accountForm.email !== currentUser.email) {
                if (auth.currentUser && auth.currentUser.uid !== 'test-user-id') {
                    await verifyBeforeUpdateEmail(auth.currentUser, accountForm.email);
                    emailChanged = true;
                } else if (auth.currentUser?.uid === 'test-user-id') {
                    showToast(t('profile.testAccountMock'));
                    return;
                }
            }

            dispatch({
                type: 'UPDATE_MEMBER',
                payload: { id: state.currentUser, email: accountForm.email, phone: accountForm.phone }
            });

            setExpanded(null);
            showToast(emailChanged ? t('profile.verifyEmailSent') : t('profile.accountInfoUpdated'));
        } catch (error) {
            showToast(error.code === 'auth/requires-recent-login' ? t('profile.reauthRequired') : t('profile.emailUpdateError') + " " + error.message, 'error');
        }
    };

    const handleSaveSettings = (e) => {
        e.preventDefault();
        const newSettings = { ...state.settings, language: language.toLowerCase() };
        dispatch({ type: 'UPDATE_SETTINGS', payload: newSettings });
        dispatch({ type: 'UPDATE_MEMBER', payload: { id: state.currentUser, settings: newSettings } });
        i18n.changeLanguage(language.toLowerCase());
        setExpanded(null);
        showToast(t('settings.saved'));
    };

    const handleThemeChange = () => {
        const newTheme = theme === 'dark' ? 'light' : 'dark';
        if (newTheme === 'dark') document.documentElement.classList.add('dark');
        else document.documentElement.classList.remove('dark');

        const newSettings = { ...state.settings, theme: newTheme };
        dispatch({ type: 'UPDATE_SETTINGS', payload: newSettings });
        dispatch({ type: 'UPDATE_MEMBER', payload: { id: state.currentUser, settings: newSettings } });
    };

    const handleFrequencyChange = (e) => {
        const value = e.target.value;
        const newSettings = { ...state.settings, reminderFrequency: value };
        dispatch({ type: 'UPDATE_SETTINGS', payload: newSettings });
        dispatch({ type: 'UPDATE_MEMBER', payload: { id: state.currentUser, settings: newSettings } });
        showToast(t('profile.reminderUpdated'));
    };

    const handleLogout = () => {
        if (window.confirm(t('profile.logoutConfirm'))) {
            sessionStorage.removeItem('MOCK_FIREBASE_USER');
            navigate('/login');
            window.location.reload();
        }
    };

    const handleDeleteAccount = async () => {
        if (!window.confirm(t('profile.deleteAccountConfirm'))) return;
        try {
            if (auth.currentUser?.uid === 'test-user-id') {
                showToast(t('profile.testAccountMock'));
                return;
            }
            await dbService.anonymizeUser(auth.currentUser.uid);
            await deleteUser(auth.currentUser);
            sessionStorage.removeItem('MOCK_FIREBASE_USER');
            localStorage.clear();
            navigate('/login');
            window.location.reload();
        } catch (error) {
            showToast(error.code === 'auth/requires-recent-login' ? t('profile.deleteReauthRequired') : t('profile.emailUpdateError') + ' ' + error.message, 'error');
        }
    };

    return (
        <div className="page-content animate-fade-in flex flex-col gap-xl" style={{ maxWidth: '600px', margin: '0 auto', width: '100%', minWidth: 0, paddingBottom: '100px' }}>
            {/* 1. Header */}
            <div className="flex flex-col items-center gap-md text-center mt-md">
                <AvatarPicker
                    selectedId={currentUser?.avatarId || 1}
                    onSelect={(avatarId) => dispatch({ type: 'UPDATE_MEMBER', payload: { id: state.currentUser, avatarId } })}
                    userName={currentUser?.name || t('profile.userIdentity')}
                    subtitle={t('profile.selectAvatar')}
                />
            </div>

            {/* 2. IBAN Card */}
            <IbanCard
                iban={currentUser?.iban}
                onSave={(iban) => dispatch({ type: 'UPDATE_MEMBER', payload: { id: state.currentUser, iban } })}
                onCopy={() => { }} // Internal feedback handles it
            />

            {/* 3. Action List Accordion */}
            <div className="glass-card stagger-2" style={{ padding: 0, overflow: 'hidden' }}>
                <div className="action-list">
                    <AccountSection
                        expanded={expanded === 'account'}
                        onToggle={setExpanded}
                        form={accountForm}
                        onChange={(key, val) => setAccountForm({ ...accountForm, [key]: val })}
                        onSubmit={handleSaveAccount}
                        itemStyle={itemStyle}
                        expandableStyle={expandableStyle}
                    />
                    <div className="divider" style={dividerStyle} />

                    <NotificationSection
                        expanded={expanded === 'notifications'}
                        onToggle={setExpanded}
                        pushEnabled={pushEnabled}
                        onPushToggle={() => handleToggleNotification('push')}
                        emailEnabled={emailEnabled}
                        onEmailToggle={() => handleToggleNotification('email')}
                        frequency={reminderFrequency}
                        onFrequencyChange={handleFrequencyChange}
                        itemStyle={itemStyle}
                        expandableStyle={expandableStyle}
                        dividerStyle={dividerStyle}
                    />
                    <div className="divider" style={dividerStyle} />

                    <AppSettingsSection
                        expanded={expanded === 'settings'}
                        onToggle={setExpanded}
                        language={language}
                        onLanguageChange={(lang) => i18n.changeLanguage(lang.toLowerCase())}
                        theme={theme}
                        onThemeToggle={handleThemeChange}
                        onSubmit={(e) => { e.preventDefault(); setExpanded(null); showToast(t('settings.saved')); }}
                        itemStyle={itemStyle}
                        expandableStyle={expandableStyle}
                    />
                    <div className="divider" style={dividerStyle} />

                    <SecuritySection
                        expanded={expanded === 'security'}
                        onToggle={setExpanded}
                        onPasswordReset={async () => {
                            try {
                                if (auth.currentUser?.email && auth.currentUser.uid !== 'test-user-id') {
                                    await sendPasswordResetEmail(auth, auth.currentUser.email);
                                    showToast(t('profile.passwordResetEmailSent'));
                                    setExpanded(null);
                                } else showToast(t('profile.testAccountMock'));
                            } catch (e) { showToast(t('profile.passwordError') + e.message, 'error'); }
                        }}
                        itemStyle={itemStyle}
                        expandableStyle={expandableStyle}
                    />
                </div>
            </div>

            {/* 4. Logout & Delete */}
            <DangerZone onLogout={handleLogout} onDeleteAccount={handleDeleteAccount} />

            {/* Inline Styles & Toast Portal */}
            <ProfileStyles />
            {createPortal(
                <AnimatePresence>
                    {toast && <Toast message={toast.message} type={toast.type} />}
                </AnimatePresence>,
                document.body
            )}
        </div>
    );
}

// Internal Helper Components for clean Profile.jsx
const ProfileStyles = () => (
    <style>{`
        .action-item { display: flex; align-items: center; justify-content: space-between; padding: var(--space-lg) var(--space-xl); cursor: pointer; transition: background 0.2s ease; }
        .action-item:hover { background: var(--bg-glass); }
        .icon-box { width: 36px; height: 36px; border-radius: var(--radius-md); display: flex; align-items: center; justify-content: center; color: white; }
        .icon-box.purple { background: rgba(139, 92, 246, 0.2); color: var(--accent-purple-light); }
        .icon-box.amber { background: rgba(245, 158, 11, 0.2); color: var(--accent-amber-light); }
        .icon-box.cyan { background: rgba(6, 182, 212, 0.2); color: var(--accent-cyan-light); }
        .icon-box.emerald { background: rgba(16, 185, 129, 0.2); color: var(--accent-emerald-light); }
        .text-emerald { color: var(--accent-emerald-light) !important; }
    `}</style>
);

const Toast = ({ message, type }) => (
    <motion.div
        initial={{ opacity: 0, y: -20, scale: 0.95 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        exit={{ opacity: 0, y: -20, scale: 0.95 }}
        style={{
            position: 'fixed', top: 'var(--space-xl)', left: '16px', right: '16px', zIndex: 9999,
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 'var(--space-sm)',
            background: type === 'success' ? 'rgba(16, 185, 129, 0.95)' : 'rgba(239, 68, 68, 0.95)',
            color: 'white', padding: '12px 20px', borderRadius: '100px', fontSize: 'var(--font-sm)',
            fontWeight: 500, boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.2)', margin: '0 auto', width: 'max-content', maxWidth: 'calc(100vw - 32px)'
        }}
    >
        {type === 'success' ? <Check size={16} /> : <AlertCircle size={16} />}
        {message}
    </motion.div>
);

const itemStyle = { minHeight: '72px' };
const expandableStyle = { padding: 'var(--space-md) var(--space-xl) var(--space-xl) var(--space-xl)', background: 'rgba(255, 255, 255, 0.02)', borderBottom: '1px solid rgba(255, 255, 255, 0.05)' };
const dividerStyle = { height: '1px', background: 'var(--border-primary)', margin: '0' };

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { createUserWithEmailAndPassword, sendEmailVerification, signOut } from 'firebase/auth';
import { auth, db } from '../config/firebase';
import { doc, setDoc } from 'firebase/firestore';
import { UserPlus, MailCheck } from 'lucide-react';
import { useTranslation, Trans } from 'react-i18next';

export default function Register() {
    const { t } = useTranslation();
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [success, setSuccess] = useState(false);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleRegister = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            // 1. Create user in Firebase Auth
            const userCredential = await createUserWithEmailAndPassword(auth, email, password);
            const user = userCredential.user;

            // 2. Create user document in Firestore 'users' collection
            await setDoc(doc(db, 'users', user.uid), {
                id: user.uid,
                name: name,
                email: email,
                phone: '',
                iban: '',
                isPro: false,
                isGhost: false,
                createdAt: new Date().toISOString()
            });

            // 3. Send email verification
            await sendEmailVerification(user);

            // 4. Sign out the user immediately so they must verify and log in
            await signOut(auth);

            setSuccess(true);
        } catch (err) {
            console.error('Registration error:', err);
            let message = t('auth.registerFailed');

            if (err.code === 'auth/email-already-in-use') {
                message = t('auth.emailInUse');
            } else if (err.code === 'auth/invalid-email') {
                message = t('auth.invalidEmail');
            } else if (err.code === 'auth/weak-password') {
                message = t('auth.weakPassword');
            } else if (err.code === 'auth/network-request-failed') {
                message = t('auth.networkError');
            }

            setError(message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="flex flex-col items-center justify-center min-h-screen p-lg">
            <div className="glass-card w-full" style={{ maxWidth: 420, padding: 'var(--space-2xl)' }}>
                {success ? (
                    <div className="flex flex-col items-center text-center">
                        <div style={{
                            width: 64, height: 64, borderRadius: '50%', background: 'rgba(16, 185, 129, 0.1)',
                            display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: 'var(--space-lg)',
                            color: 'var(--accent-emerald)'
                        }}>
                            <MailCheck size={32} />
                        </div>
                        <h2 style={{ fontSize: 'var(--font-xl)', fontWeight: 800, marginBottom: 'var(--space-sm)' }}>{t('auth.emailSentTitle')}</h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: '0.95rem', marginBottom: 'var(--space-xl)', lineHeight: 1.5 }}>
                            <Trans i18nKey="auth.emailSentDesc" values={{ email: email }} />
                        </p>
                        <Link to="/login" className="btn btn-primary w-full flex justify-center" style={{ padding: '12px' }}>
                            {t('auth.backToLogin')}
                        </Link>
                    </div>
                ) : (
                    <>
                        <div className="flex flex-col items-center mb-xl">
                            <img
                                src="/icon.png"
                                alt="CoBill Logo"
                                style={{ width: 80, height: 80, objectFit: 'contain', marginBottom: 'var(--space-md)' }}
                            />
                            <h2 style={{ fontSize: 'var(--font-2xl)', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '4px' }}>{t('auth.registerTitle')}</h2>
                            <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', textAlign: 'center' }}>
                                {t('auth.registerSubtitle')}
                            </p>
                        </div>

                        {error && (
                            <div className="mb-lg p-md" style={{ background: 'rgba(244, 63, 94, 0.1)', color: 'var(--accent-rose)', borderRadius: 'var(--radius-md)', fontSize: '13px' }}>
                                {error}
                            </div>
                        )}

                        <form onSubmit={handleRegister} className="flex flex-col gap-md">
                            <div className="form-group">
                                <label>{t('auth.fullNameLabel')}</label>
                                <input
                                    type="text"
                                    className="form-input"
                                    value={name}
                                    onChange={e => setName(e.target.value)}
                                    placeholder={t('auth.fullNamePlaceholder')}
                                    required
                                />
                            </div>
                            <div className="form-group">
                                <label>{t('auth.emailLabel')}</label>
                                <input
                                    type="email"
                                    className="form-input"
                                    value={email}
                                    onChange={e => setEmail(e.target.value)}
                                    placeholder={t('auth.emailPlaceholder')}
                                    required
                                />
                            </div>
                            <div className="form-group">
                                <label>{t('auth.passwordLabel')}</label>
                                <input
                                    type="password"
                                    className="form-input"
                                    value={password}
                                    onChange={e => setPassword(e.target.value)}
                                    placeholder={t('auth.passwordPlaceholder')}
                                    required
                                    minLength={6}
                                />
                            </div>

                            <button
                                type="submit"
                                className="btn btn-primary w-full mt-lg flex items-center justify-center gap-sm"
                                style={{ background: 'var(--gradient-primary)', padding: '14px', fontSize: '1rem', fontWeight: 600 }}
                                disabled={loading}
                            >
                                {loading ? t('auth.registering') : <><UserPlus size={20} /> {t('auth.registerButton')}</>}
                            </button>
                        </form>

                        <div className="text-center mt-xl pt-lg" style={{ borderTop: '1px solid var(--border-primary)' }}>
                            <p style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                                {t('auth.alreadyHaveAccount')}{' '}
                                <Link to="/login" style={{ color: 'var(--accent-purple)', fontWeight: 700, textDecoration: 'none' }}>
                                    {t('auth.loginButton')}
                                </Link>
                            </p>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
}

import { useState } from 'react';
import { useApp } from '../context/AppContext';
import { SlidersHorizontal, Sparkles } from 'lucide-react';
import ProUpgradeModal from '../components/ProUpgradeModal';
import AIReportModal from '../components/AIReportModal';
import { generateAIReport } from '../services/aiService';
import { getDateRange, filterByDateRange } from '../utils/dateFilterUtils';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { motion, AnimatePresence } from 'framer-motion';

// Sub-components
import NonProReportsView from '../components/reports/NonProReportsView';
import GroupReportsTab from '../components/reports/GroupReportsTab';
import PersonalReportsTab from '../components/reports/PersonalReportsTab';
import FilterModal from '../components/reports/FilterModal';

export default function Reports() {
    const { state } = useApp();
    const { t } = useTranslation();
    const [selectedGroup, setSelectedGroup] = useState(state.groups[0]?.id || '');
    const [showProModal, setShowProModal] = useState(false);
    const [reportTab, setReportTab] = useState('group'); // 'group' | 'personal'
    const [showFilterModal, setShowFilterModal] = useState(false);
    const [dateFilter, setDateFilter] = useState(getDateRange('all'));

    // AI Report state
    const [showAIReport, setShowAIReport] = useState(false);
    const [aiReportHtml, setAiReportHtml] = useState(null);
    const [aiReportLoading, setAiReportLoading] = useState(false);
    const [aiReportError, setAiReportError] = useState(null);
    const [toast, setToast] = useState(null);

    const isPro = state.members[state.currentUser]?.isPro;
    const group = state.groups.find(g => g.id === selectedGroup);

    const showToast = (message, type = 'success') => {
        setToast({ message, type });
        setTimeout(() => setToast(null), 3000);
    };

    if (!isPro) {
        return (
            <>
                <NonProReportsView
                    groups={state.groups}
                    selectedGroup={selectedGroup}
                    setSelectedGroup={setSelectedGroup}
                    setShowProModal={setShowProModal}
                    t={t}
                />
                {showProModal && <ProUpgradeModal onClose={() => setShowProModal(false)} />}
            </>
        );
    }

    // PRO Logic: Data Filtering
    let expenses = state.expenses.filter(e => e.groupId === selectedGroup);
    let groupSettlements = state.settlements.filter(s => s.groupId === selectedGroup && s.status === 'paid');
    let personalFilteredExpenses = state.personalExpenses;

    if (dateFilter) {
        expenses = filterByDateRange(expenses, dateFilter.startDate, dateFilter.endDate);
        groupSettlements = filterByDateRange(groupSettlements, dateFilter.startDate, dateFilter.endDate);
        personalFilteredExpenses = filterByDateRange(personalFilteredExpenses, dateFilter.startDate, dateFilter.endDate);
    }

    const totalSpent = expenses.reduce((s, e) => s + e.amount, 0);
    const personalTotal = personalFilteredExpenses.reduce((s, e) => s + e.amount, 0);

    const categoryBreakdown = {};
    expenses.forEach(e => {
        const cat = e.category || 'other';
        categoryBreakdown[cat] = (categoryBreakdown[cat] || 0) + e.amount;
    });

    const personalCategoryBreakdown = {};
    personalFilteredExpenses.forEach(e => {
        personalCategoryBreakdown[e.category] = (personalCategoryBreakdown[e.category] || 0) + e.amount;
    });

    const handleGenerateAIReport = async () => {
        let reportExpenses, contextData;
        const limitKey = 'cobill_ai_limits';
        const todayStr = new Date().toISOString().split('T')[0];

        if (reportTab === 'group' && group) {
            reportExpenses = expenses;
            const memberNames = {};
            group.members.forEach(id => { memberNames[id] = state.members[id]?.name; });
            contextData = { groupName: group.name, memberCount: group.members.length, currency: group.currency, memberNames };
        } else {
            reportExpenses = personalFilteredExpenses;
            contextData = {};
        }

        const expenseSum = reportExpenses.reduce((sum, e) => sum + e.amount, 0);
        const lastExpenseId = reportExpenses.length > 0 ? reportExpenses[reportExpenses.length - 1].id : 'none';
        const signature = `${reportExpenses.length}_${expenseSum}_${lastExpenseId}`;

        let aiLimits = JSON.parse(localStorage.getItem(limitKey) || '{"date":"","group":0,"personal":0}');
        if (aiLimits.date !== todayStr) aiLimits = { date: todayStr, group: 0, personal: 0 };

        const cacheKey = `cobill_ai_cache_${reportTab}_${selectedGroup || 'personal'}`;
        const cachedData = JSON.parse(localStorage.getItem(cacheKey) || 'null');

        setShowAIReport(true);

        if (cachedData && cachedData.signature === signature && cachedData.html) {
            setAiReportHtml(cachedData.html);
            setAiReportError(null);
            showToast(t('aiReport.ready'), 'success');
            return;
        }

        if (aiLimits[reportTab] >= 3) {
            setAiReportHtml(null);
            setAiReportLoading(false);
            setAiReportError(t('aiReport.limitExceeded'));
            showToast(t('aiReport.limitReached'), 'error');
            return;
        }

        setAiReportHtml(null);
        setAiReportError(null);
        setAiReportLoading(true);

        try {
            const html = await generateAIReport(reportExpenses, reportTab, contextData);
            setAiReportHtml(html);
            aiLimits[reportTab] += 1;
            localStorage.setItem(limitKey, JSON.stringify(aiLimits));
            localStorage.setItem(cacheKey, JSON.stringify({ signature, html }));
            showToast(t('aiReport.success'), 'success');
        } catch (err) {
            setAiReportError(err.message || t('aiReport.error'));
        } finally {
            setAiReportLoading(false);
        }
    };

    return (
        <div className="animate-fade-in relative">
            <div className="page-header">
                <div>
                    <h2>{t('reports.pageTitle')} <span className="badge badge-pro-gold" style={{ marginLeft: 8, verticalAlign: 'middle' }}>PRO</span></h2>
                    <p className="page-subtitle">{t('reports.pageSubtitle')}</p>
                </div>
                <div className="flex gap-sm">
                    <button
                        className="btn ai-report-generate-btn"
                        onClick={handleGenerateAIReport}
                        disabled={reportTab === 'group' && !group}
                    >
                        <Sparkles size={14} /> {t('aiReport.generateButton')}
                    </button>
                </div>
            </div>

            {/* Segmented Control */}
            <div className="flex gap-xs mb-xl" style={{ background: 'var(--bg-glass)', borderRadius: 'var(--radius-lg)', padding: 4, border: '1px solid var(--border-primary)', maxWidth: 400 }}>
                <button className={`btn btn-sm ${reportTab === 'group' ? 'btn-primary' : 'btn-ghost'}`} onClick={() => setReportTab('group')} style={{ flex: 1, borderRadius: 'var(--radius-md)', fontWeight: 600 }}>👥 {t('reports.groupReports')}</button>
                <button className={`btn btn-sm ${reportTab === 'personal' ? 'btn-primary' : 'btn-ghost'}`} onClick={() => setReportTab('personal')} style={{ flex: 1, borderRadius: 'var(--radius-md)', fontWeight: 600 }}>👤 {t('reports.personalReports')}</button>
            </div>

            <div style={{ marginBottom: 'var(--space-xl)', display: 'flex', justifyContent: 'flex-start' }}>
                <button className="btn btn-secondary btn-sm" onClick={() => setShowFilterModal(true)} style={{ display: 'inline-flex', alignItems: 'center', gap: '6px', padding: '6px 14px', minHeight: '36px', fontSize: '0.82rem', borderRadius: 'var(--radius-md)' }}>
                    <SlidersHorizontal size={14} /> <span>{t('reports.filter')}</span>
                    {(dateFilter.startDate || dateFilter.endDate) && <span style={{ background: 'var(--gradient-primary)', color: 'white', fontSize: '10px', fontWeight: 800, width: '18px', height: '18px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', marginLeft: '2px' }}>1</span>}
                </button>
            </div>

            {reportTab === 'group' ? (
                <>
                    <div className="form-group mb-xl" style={{ maxWidth: 300 }}>
                        <label className="form-label">{t('reports.selectGroup')}</label>
                        <select className="form-select" value={selectedGroup} onChange={e => setSelectedGroup(e.target.value)}>
                            {state.groups.map(g => (<option key={g.id} value={g.id}>{g.name}</option>))}
                        </select>
                    </div>
                    <GroupReportsTab
                        selectedGroup={selectedGroup} groups={state.groups} group={group}
                        expenses={expenses} totalSpent={totalSpent} groupSettlements={groupSettlements}
                        categoryBreakdown={categoryBreakdown} dateFilter={dateFilter} t={t} state={state}
                    />
                </>
            ) : (
                <PersonalReportsTab
                    personalTotal={personalTotal}
                    personalExpensesCount={personalFilteredExpenses.length}
                    personalCategoryBreakdown={personalCategoryBreakdown}
                    t={t}
                />
            )}

            <AIReportModal isOpen={showAIReport} onClose={() => setShowAIReport(false)} reportHtml={aiReportHtml} isLoading={aiReportLoading} error={aiReportError} />
            {showProModal && <ProUpgradeModal onClose={() => setShowProModal(false)} />}

            <FilterModal
                isOpen={showFilterModal}
                onClose={() => setShowFilterModal(false)}
                dateFilter={dateFilter}
                onDateFilterChange={setDateFilter}
                t={t}
            />

            {createPortal(
                <AnimatePresence>
                    {toast && (
                        <motion.div
                            initial={{ opacity: 0, y: 50, scale: 0.9 }}
                            animate={{ opacity: 1, y: 0, scale: 1 }}
                            exit={{ opacity: 0, y: 20, scale: 0.9 }}
                            style={{
                                position: 'fixed', bottom: 'calc(var(--space-2xl) + 60px)', left: '50%', transform: 'translateX(-50%)', zIndex: 99999,
                                background: toast.type === 'error' ? 'var(--accent-red)' : 'var(--bg-glass)', border: `1px solid ${toast.type === 'error' ? 'rgba(255,0,0,0.3)' : 'var(--border-primary)'}`,
                                color: toast.type === 'error' ? 'white' : 'var(--text-primary)', WebkitBackdropFilter: 'blur(20px)', backdropFilter: 'blur(20px)', padding: '12px 24px', borderRadius: 'var(--radius-full)',
                                display: 'flex', alignItems: 'center', gap: '10px', boxShadow: '0 8px 30px rgba(0,0,0,0.15)', fontWeight: 600, fontSize: '0.9rem', whiteSpace: 'nowrap'
                            }}
                        >
                            {toast.type === 'success' ? '✨' : '⚠️'} {toast.message}
                        </motion.div>
                    )}
                </AnimatePresence>,
                document.body
            )}
        </div>
    );
}

import { useState } from 'react';
import { CheckCircle2, Clock, ArrowRight, Zap } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { calculateBalances, simplifyDebts } from '../utils/debtSimplification';
import { formatCurrency } from '../utils/currencyUtils';
import { getInitials, getAvatarImage, generateId } from '../utils/helpers';
import { showInterstitialAd } from '../utils/adService';
import NudgeButton from '../components/NudgeButton';
import { useTranslation, Trans } from 'react-i18next';

export default function Settlements() {
    const { state, dispatch } = useApp();
    const { t } = useTranslation();
    const [filter, setFilter] = useState('pending'); // pending | all | paid
    const [pendingPayment, setPendingPayment] = useState(null);

    // Calculate all simplified debts across all groups
    const allTransactions = [];

    state.groups.forEach(group => {
        const members = group.members.map(id => state.members[id]).filter(Boolean);
        const expenses = state.expenses.filter(e => e.groupId === group.id);
        const balances = calculateBalances(expenses, members);
        const transactions = simplifyDebts(balances);

        transactions.forEach(tx => {
            // Check if already settled
            const isSettled = state.settlements.some(
                s => s.groupId === group.id && s.from === tx.from && s.to === tx.to && s.status === 'paid'
                    && Math.abs(s.amount - tx.amount) < 1
            );

            allTransactions.push({
                ...tx,
                groupId: group.id,
                groupName: group.name,
                currency: group.currency,
                isSettled,
            });
        });
    });

    // Settlement history
    const history = state.settlements.filter(s => s.status === 'paid');

    const handleMarkPaid = (tx) => {
        setPendingPayment(tx);
    };

    const confirmPayment = () => {
        if (!pendingPayment) return;
        const tx = pendingPayment;
        const settlement = {
            id: generateId(),
            groupId: tx.groupId,
            from: tx.from,
            to: tx.to,
            amount: tx.amount,
            currency: tx.currency,
            status: 'paid',
            date: new Date().toISOString(),
            paidAt: new Date().toISOString(),
        };
        dispatch({ type: 'ADD_SETTLEMENT', payload: settlement });

        setPendingPayment(null);

        // Brief visual feedback for the user (can rely on React state updates visually too)

        const isPro = state.members[state.currentUser]?.isPro;
        if (!isPro) {
            // Trigger interstitial AD after user finishes core confirmation action
            setTimeout(() => showInterstitialAd(), 300);
        }
    };

    const pendingTx = allTransactions.filter(t => !t.isSettled);
    const totalPending = pendingTx.reduce((s, t) => s + t.amount, 0);

    return (
        <div className="animate-fade-in">
            <div className="page-header">
                <div>
                    <h2>{t('settlements.pageTitle')}</h2>
                    <p className="page-subtitle">{t('settlements.pageSubtitle')}</p>
                </div>
            </div>

            {/* Summary Stats */}
            <div className="grid grid-3 mb-xl mobile-scroller" style={{ gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))' }}>
                <div className="stat-card animate-fade-in-up stagger-1">
                    <div className="stat-icon" style={{ background: 'rgba(245, 158, 11, 0.15)', color: 'var(--accent-amber)' }}>
                        <Clock size={22} />
                    </div>
                    <div className="stat-value" style={{ color: 'var(--accent-amber-light)' }}>{pendingTx.length}</div>
                    <div className="stat-label">{t('settlements.pendingPayment')}</div>
                </div>
                <div className="stat-card animate-fade-in-up stagger-2">
                    <div className="stat-icon" style={{ background: 'rgba(16, 185, 129, 0.15)', color: 'var(--accent-emerald)' }}>
                        <CheckCircle2 size={22} />
                    </div>
                    <div className="stat-value" style={{ color: 'var(--accent-emerald-light)' }}>{history.length}</div>
                    <div className="stat-label">{t('settlements.completed')}</div>
                </div>
                <div className="stat-card animate-fade-in-up stagger-3">
                    <div className="stat-icon" style={{ background: 'rgba(139, 92, 246, 0.15)', color: 'var(--accent-purple)' }}>
                        <Zap size={22} />
                    </div>
                    <div className="stat-value text-gradient">{allTransactions.length}</div>
                    <div className="stat-label">{t('settlements.totalTransactions')}</div>
                </div>
            </div>

            {/* Filter Tabs */}
            <div className="flex gap-sm mb-xl">
                {[
                    { id: 'pending', label: t('settlements.pending'), count: pendingTx.length },
                    { id: 'paid', label: t('settlements.paid'), count: history.length },
                    { id: 'all', label: t('settlements.all'), count: allTransactions.length },
                ].map(tab => (
                    <button
                        key={tab.id}
                        className={`btn ${filter === tab.id ? 'btn-primary' : 'btn-secondary'} btn-sm`}
                        onClick={() => setFilter(tab.id)}
                    >
                        {tab.label}
                        <span className="badge badge-purple" style={{
                            background: filter === tab.id ? 'rgba(255,255,255,0.2)' : undefined,
                            color: filter === tab.id ? 'white' : undefined,
                            border: 'none',
                            marginLeft: 4,
                        }}>
                            {tab.count}
                        </span>
                    </button>
                ))}
            </div>

            {/* Pending Transactions */}
            {(filter === 'pending' || filter === 'all') && pendingTx.length > 0 && (
                <div className="glass-card mb-xl">
                    <h4 className="mb-lg">{t('settlements.pendingPayments')}</h4>
                    <div className="flex flex-col gap-md">
                        {pendingTx.map((tx, i) => {
                            const fromMember = state.members[tx.from];
                            const toMember = state.members[tx.to];

                            return (
                                <div key={`${tx.from}-${tx.to}-${i}`} className={`animate-fade-in-up stagger-${Math.min(i + 1, 6)}`} style={{
                                    padding: 'var(--space-lg)',
                                    background: 'var(--bg-glass)',
                                    borderRadius: 'var(--radius-lg)',
                                    border: '1px solid var(--border-primary)',
                                    display: 'flex',
                                    flexDirection: 'column',
                                    gap: 'var(--space-md)',
                                    boxShadow: '0 4px 20px rgba(0, 0, 0, 0.05)'
                                }}>
                                    {/* Group Name Badge (Top Center) */}
                                    <div className="flex justify-center w-full mb-xs">
                                        <span style={{
                                            background: 'rgba(255, 255, 255, 0.05)',
                                            border: '1px solid var(--border-primary)',
                                            padding: '4px 12px',
                                            borderRadius: '20px',
                                            fontSize: '11px',
                                            color: 'var(--text-secondary)',
                                            fontWeight: 600,
                                            letterSpacing: '0.5px'
                                        }}>
                                            {tx.groupName}
                                        </span>
                                    </div>

                                    {/* Middle section: Transaction Info */}
                                    <div className="flex items-center justify-between w-full">
                                        {/* From */}
                                        <div className="flex flex-col items-center gap-xs" style={{ width: '80px' }}>
                                            <img src={getAvatarImage(fromMember?.avatarId || 1)} alt={fromMember?.name || '?'} className="avatar" style={{ width: 44, height: 44, objectFit: 'cover' }} />
                                            <div className="text-sm font-semibold truncate w-full text-center" title={fromMember?.name}>{fromMember?.name?.split(' ')[0]}</div>
                                            <div className="text-xs text-muted">{t('settlements.willPay')}</div>
                                        </div>

                                        {/* Amount & Arrow */}
                                        <div className="flex flex-col items-center justify-center flex-1 px-sm">
                                            <div className="font-bold text-lg" style={{ color: 'var(--accent-amber-light)', marginBottom: 4 }}>
                                                {formatCurrency(tx.amount, tx.currency)}
                                            </div>
                                            <div style={{ width: '100%', height: 2, background: 'var(--gradient-primary)', position: 'relative' }}>
                                                <ArrowRight size={16} style={{ position: 'absolute', right: -2, top: '50%', transform: 'translateY(-50%)', color: 'var(--accent-cyan)' }} />
                                            </div>
                                        </div>

                                        {/* To */}
                                        <div className="flex flex-col items-center gap-xs" style={{ width: '80px' }}>
                                            <img src={getAvatarImage(toMember?.avatarId || 1)} alt={toMember?.name || '?'} className="avatar" style={{ width: 44, height: 44, objectFit: 'cover' }} />
                                            <div className="text-sm font-semibold truncate w-full text-center" title={toMember?.name}>{toMember?.name?.split(' ')[0]}</div>
                                            <div className="text-xs text-muted">{t('settlements.creditor')}</div>
                                        </div>
                                    </div>

                                    {/* Action Buttons (Stacked) */}
                                    <div className="flex flex-col gap-sm w-full mt-sm" style={{ borderTop: '1px solid var(--border-primary)', paddingTop: 'var(--space-md)' }}>
                                        <button
                                            className="btn btn-success flex justify-center items-center gap-xs w-full"
                                            onClick={() => handleMarkPaid(tx)}
                                            style={{ padding: '12px', fontSize: '0.9rem', fontWeight: 600, borderRadius: 'var(--radius-md)' }}
                                            title={t('settlements.confirmPaymentTooltip')}
                                        >
                                            <CheckCircle2 size={18} /> {t('settlements.completePayment')}
                                        </button>
                                        <div style={{ position: 'relative', width: '100%' }}>
                                            <NudgeButton
                                                memberId={tx.from}
                                                amount={tx.amount}
                                                groupName={tx.groupName}
                                                currency={tx.currency}
                                            />
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            {/* Paid History */}
            {(filter === 'paid' || filter === 'all') && history.length > 0 && (
                <div className="glass-card">
                    <h4 className="mb-lg">{t('settlements.paymentHistory')}</h4>
                    <div className="flex flex-col gap-sm">
                        {history.map((s, i) => {
                            const fromMember = state.members[s.from];
                            const toMember = state.members[s.to];
                            const group = state.groups.find(g => g.id === s.groupId);

                            return (
                                <div key={s.id} className="flex items-center gap-md" style={{
                                    padding: 'var(--space-md)',
                                    background: 'var(--bg-glass)',
                                    borderRadius: 'var(--radius-md)',
                                    opacity: 0.7,
                                }}>
                                    <CheckCircle2 size={18} style={{ color: 'var(--accent-emerald)', flexShrink: 0 }} />
                                    <div style={{ flex: 1 }}>
                                        <div className="text-sm">
                                            <strong>{fromMember?.name?.split(' ')[0]}</strong> → <strong>{toMember?.name?.split(' ')[0]}</strong>
                                        </div>
                                        <div className="text-xs text-muted">{group?.name}</div>
                                    </div>
                                    <div className="text-sm font-bold" style={{ color: 'var(--accent-emerald)' }}>
                                        {formatCurrency(s.amount, s.currency)}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            {/* Empty state */}
            {filter === 'pending' && pendingTx.length === 0 && (
                <div className="empty-state glass-card">
                    <div className="empty-icon">🎉</div>
                    <h3>{t('settlements.allDebtsPaid')}</h3>
                    <p className="text-sm">{t('settlements.noPendingPayment')}</p>
                </div>
            )}

            {/* Payment Confirmation Modal */}
            {pendingPayment && (
                <div className="modal-overlay" onClick={() => setPendingPayment(null)} style={{ zIndex: 3000 }}>
                    <div className="modal-content animate-fade-in-up" onClick={e => e.stopPropagation()} style={{ maxWidth: 400, textAlign: 'center', padding: 'var(--space-2xl) var(--space-xl)' }}>
                        <div className="flex items-center justify-center mx-auto mb-lg" style={{ background: 'rgba(16, 185, 129, 0.15)', color: 'var(--accent-emerald)', width: 64, height: 64, borderRadius: '50%' }}>
                            <CheckCircle2 size={32} />
                        </div>
                        <h3 className="mb-sm text-lg font-bold">{t('settlements.confirmPaymentModalTitle')}</h3>
                        <p className="text-muted mb-xl text-sm" style={{ lineHeight: 1.5 }}>
                            <Trans
                                i18nKey="settlements.confirmPaymentMessage"
                                values={{
                                    name: state.members[pendingPayment.from]?.name?.split(' ')[0],
                                    amount: formatCurrency(pendingPayment.amount, pendingPayment.currency)
                                }}
                            />
                        </p>
                        <div className="flex gap-md w-full">
                            <button className="btn btn-secondary flex-1" onClick={() => setPendingPayment(null)}>
                                {t('settlements.cancel')}
                            </button>
                            <button className="btn btn-success flex-1" onClick={confirmPayment}>
                                {t('settlements.yesComplete')}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { Capacitor } from '@capacitor/core';
import { AdMob, BannerAdPosition, BannerAdSize } from '@capacitor-community/admob';

// Test IDs provided by Google AdMob
const ADMOB_TEST_BANNER_ID = Capacitor.getPlatform() === 'ios'
    ? 'ca-app-pub-3940256099942544/2934735716'
    : 'ca-app-pub-3940256099942544/6300978111';

const ADMOB_TEST_INTERSTITIAL_ID = Capacitor.getPlatform() === 'ios'
    ? 'ca-app-pub-3940256099942544/4411468910'
    : 'ca-app-pub-3940256099942544/1033173712';

let isAdmobInitialized = false;

export async function initializeAdMob() {
    if (!Capacitor.isNativePlatform()) {
        console.log('[AdMob] Not on native platform. AdMob initialization skipped.');
        return;
    }

    try {
        await AdMob.initialize({
            requestTrackingAuthorization: true,
            initializeForTesting: true,
        });
        isAdmobInitialized = true;
        console.log('[AdMob] Initialized successfully.');

        // Force remove any leftover banners from previous app sessions just in case
        try {
            await AdMob.removeBanner();
            console.log('[AdMob] Banner removed explicitly.');
        } catch (e) {
            // Ignore errors if banner wasn't showing
        }
    } catch (e) {
        console.error('[AdMob] Failed to initialize:', e);
    }
}

export async function showInterstitialAd() {
    if (!Capacitor.isNativePlatform() || !isAdmobInitialized) {
        return Promise.resolve(); // Resolves immediately if not on mobile/not initialized
    }

    return new Promise(async (resolve) => {
        let isResolved = false;

        const cleanupAndResolve = () => {
            if (!isResolved) {
                isResolved = true;
                resolve();
            }
        };

        try {
            // Prepare ad
            await AdMob.prepareInterstitial({
                adId: ADMOB_TEST_INTERSTITIAL_ID,
                isTesting: true,
            });

            // Listeners for dismissal or failure to ensure navigation continues
            AdMob.addListener('interstitialDismissed', () => {
                console.log('[AdMob] Interstitial dismissed.');
                cleanupAndResolve();
            });

            AdMob.addListener('interstitialFailedToLoad', (error) => {
                console.warn('[AdMob] Interstitial failed to load:', error);
                cleanupAndResolve();
            });

            // Show ad
            await AdMob.showInterstitial();
            console.log('[AdMob] Interstitial shown.');

            // Fallback timeout just in case events fail to trigger
            setTimeout(() => {
                cleanupAndResolve();
            }, 10000); // 10 seconds max wait for ad to do something

        } catch (e) {
            console.error('[AdMob] Failed to show interstitial:', e);
            cleanupAndResolve();
        }
    });
}

import { Filesystem, Directory } from '@capacitor/filesystem';
import { Share } from '@capacitor/share';
import { Capacitor } from '@capacitor/core';

export const sharePDF = async (base64Data, filename = 'rapor.pdf') => {
    try {
        // base64Data comes as "data:application/pdf;filename=generated.pdf;base64,JVBERi..."
        // We need to strip the prefix to save it via capacitor filesystem
        const base64Content = base64Data.split('base64,')[1];

        if (!base64Content) {
            throw new Error('Invalid Base64 data');
        }

        // 1. Save file to cache directory temporarily
        const writeResult = await Filesystem.writeFile({
            path: filename,
            data: base64Content,
            directory: Directory.Cache,
        });

        // 2. Share the local file via native share sheet
        if (Capacitor.isNativePlatform()) {
            await Share.share({
                title: i18n.t('sharing.reportTitle'),
                text: i18n.t('sharing.reportText'),
                url: writeResult.uri,
                dialogTitle: i18n.t('sharing.dialogTitle'),
            });
            console.log('[fileService] PDF shared successfully natively');
        } else {
            // Fallback for Web/Browser Testing
            const link = document.createElement('a');
            link.href = base64Data;
            link.download = filename;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            console.log('[fileService] PDF downloaded via browser fallback');
        }
    } catch (error) {
        console.error('[fileService] Error sharing PDF:', error);
        throw error;
    }
};

